app.use((req, res, next) => {
  try {
    if (req.session) {
      if (!req.session.oppusApiTk) req.session.oppusApiTk = crypto.randomBytes(18).toString('hex');
      res.locals.OPPUS_API_TK = String(req.session.oppusApiTk || '');
    } else {
      res.locals.OPPUS_API_TK = '';
    }
  } catch (_) { res.locals.OPPUS_API_TK = ''; }
  const isSandbox = process.env.EFI_SANDBOX === 'true';
  res.locals.EFI_SANDBOX = isSandbox;
  res.locals.EFI_PAYEE_CODE = process.env.EFI_PAYEE_CODE || '';
  const official = isSandbox
    ? 'https://sandbox.efipay.com.br/v1/payment-token.js'
    : 'https://payment-token.efipay.com.br/v1/payment-token.js';
  res.locals.EFI_SCRIPT_URL = official;
  res.locals.EFI_SCRIPT_FALLBACK_URL = 'https://cdn.jsdelivr.net/gh/efipay/js-payment-token-efi/dist/payment-token-efi.min.js';
  const pagarmeKeys = getPagarmeKeys();
  res.locals.PAGARME_PUBLIC_KEY = pagarmeKeys.public || '';
  const stripeKeys = getStripeKeys();
  res.locals.STRIPE_PUBLISHABLE_KEY = stripeKeys.publishable || '';
  res.locals.CARD_PROVIDER = (stripeKeys.publishable && stripeKeys.secret) ? 'stripe' : 'pagarme';
  res.locals.STRIPE_USE_CHECKOUT = String(process.env.STRIPE_USE_CHECKOUT || '').toLowerCase() === 'true';
  res.locals.PAGARME_INSTALLMENTS_MAX = (function () {
    const n = parseInt(String(process.env.PAGARME_INSTALLMENTS_MAX || '12'), 10);
    if (!Number.isFinite(n) || n <= 0) return 12;
    return Math.max(1, Math.min(18, n));
  })();
  res.locals.PAGARME_INSTALLMENTS_FREE = (function () {
    const n = parseInt(String(process.env.PAGARME_INSTALLMENTS_FREE || String(res.locals.PAGARME_INSTALLMENTS_MAX || 12)), 10);
    if (!Number.isFinite(n) || n < 0) return Number(res.locals.PAGARME_INSTALLMENTS_MAX || 12);
    return Math.max(0, Math.min(Number(res.locals.PAGARME_INSTALLMENTS_MAX || 12), n));
  })();
  res.locals.PAGARME_INSTALLMENT_INTEREST_RATE = (function () {
    const raw = String(process.env.PAGARME_INSTALLMENT_INTEREST_RATE || '0').replace(',', '.').trim();
    const n = Number(raw);
    if (!Number.isFinite(n) || n <= 0) return 0;
    return Math.max(0, Math.min(25, n));
  })();
  next();
});

// Middleware melhorado para capturar IP real (útil quando atrás de proxy)
app.use((req, res, next) => {
    // Tentar diferentes headers para capturar o IP real
    let ip = req.headers['x-forwarded-for'] || 
             req.headers['x-real-ip'] || 
             req.headers['cf-connecting-ip'] || 
             req.headers['x-client-ip'] || 
             req.headers['x-forwarded'] || 
             req.headers['forwarded-for'] || 
             req.headers['forwarded'] ||
             req.connection.remoteAddress || 
             req.socket.remoteAddress || 
             req.ip || 
             'unknown';
    
    // Se x-forwarded-for contém múltiplos IPs, pegar o primeiro
    if (ip && ip.includes(',')) {
        ip = ip.split(',')[0].trim();
    }
    
    // Normalizar IPv6 mapeado para IPv4
    const ipNormalized = ip.replace('::ffff:', '');
    
    // Atribuir o IP real à requisição
    req.realIP = ipNormalized;
    req.ip = ipNormalized; // Também sobrescrever req.ip
    
    next();
});

const OPPUS_CLIENT_ID_COOKIE = 'oppus_cid';
const getCookieValue = (req, name) => {
  try {
    const cookieHeader = String((req && req.headers && req.headers['cookie']) || '');
    if (!cookieHeader) return '';
    const parts = cookieHeader.split(';');
    for (const part of parts) {
      const p = String(part || '').trim();
      if (!p) continue;
      const eq = p.indexOf('=');
      if (eq <= 0) continue;
      const k = p.slice(0, eq).trim();
      if (k !== name) continue;
      const raw = p.slice(eq + 1);
      try { return decodeURIComponent(raw); } catch (_) { return raw; }
    }
  } catch (_) {}
  return '';
};

const ensureClientIdCookie = (req, res) => {
  try {
    const existing = getCookieValue(req, OPPUS_CLIENT_ID_COOKIE);
    if (existing) return existing;
    let id = '';
    try {
      const c = require('crypto');
      if (c && typeof c.randomUUID === 'function') id = c.randomUUID();
    } catch (_) {}
    if (!id) id = `cid_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
    try {
      if (res && typeof res.cookie === 'function') {
        res.cookie(OPPUS_CLIENT_ID_COOKIE, id, { maxAge: 365 * 24 * 60 * 60 * 1000, httpOnly: false, path: '/' });
      } else if (res && typeof res.setHeader === 'function') {
        const cookie = `${OPPUS_CLIENT_ID_COOKIE}=${encodeURIComponent(id)}; Path=/; Max-Age=${365 * 24 * 60 * 60}`;
        res.setHeader('Set-Cookie', cookie);
      }
    } catch (_) {}
    return id;
  } catch (_) {}
  return '';
};

app.use((req, res, next) => {
  try {
    req.oppusClientId = ensureClientIdCookie(req, res);
  } catch (_) {}
  next();
});

const ADMIN_AUTH_COOKIE = 'oppus_admin_auth';
const adminAuthSecret = () => String(process.env.ADMIN_COOKIE_SECRET || "agencia-oppus-secret-key");
const base64UrlEnc = (buf) => Buffer.from(buf).toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
const base64UrlDec = (str) => {
  const s = String(str || '').replace(/-/g, '+').replace(/_/g, '/');
  const pad = s.length % 4 ? '='.repeat(4 - (s.length % 4)) : '';
  return Buffer.from(s + pad, 'base64');
};
const parseCookieHeader = (req) => {
  const out = {};
  const raw = String((req && req.headers && req.headers.cookie) || '');
  if (!raw) return out;
  const parts = raw.split(';');
  for (const p of parts) {
    const kv = String(p || '').trim();
    if (!kv) continue;
    const idx = kv.indexOf('=');
    if (idx < 0) continue;
    const k = kv.slice(0, idx).trim();
    const v = kv.slice(idx + 1).trim();
    if (!k) continue;
    try { out[k] = decodeURIComponent(v || ''); } catch (_) { out[k] = v || ''; }
  }
  return out;
};
const signAdminAuth = (payloadObj) => {
  const json = JSON.stringify(payloadObj || {});
  const payload = base64UrlEnc(Buffer.from(json, 'utf8'));
  const sig = base64UrlEnc(crypto.createHmac('sha256', adminAuthSecret()).update(payload).digest());
  return `${payload}.${sig}`;
};
const verifyAdminAuth = (token) => {
  try {
    const t = String(token || '');
    const idx = t.lastIndexOf('.');
    if (idx < 1) return null;
    const payload = t.slice(0, idx);
    const sig = t.slice(idx + 1);
    const expected = base64UrlEnc(crypto.createHmac('sha256', adminAuthSecret()).update(payload).digest());
    const a = Buffer.from(String(sig), 'utf8');
    const b = Buffer.from(String(expected), 'utf8');
    if (a.length !== b.length) return null;
    if (!crypto.timingSafeEqual(a, b)) return null;
    const obj = JSON.parse(base64UrlDec(payload).toString('utf8'));
    if (!obj || !obj.username) return null;
    if (obj.exp && Number(obj.exp) > 0 && Date.now() > Number(obj.exp)) return null;
    return obj;
  } catch (_) {
    return null;
  }
};
// Prazo do login do admin (sliding). Configurável via ADMIN_AUTH_TTL_DAYS, padrão 30 dias.
const ADMIN_AUTH_TTL_MS = (() => {
  const d = parseInt(String(process.env.ADMIN_AUTH_TTL_DAYS || ''), 10);
  return (Number.isFinite(d) && d > 0 ? d : 30) * 24 * 60 * 60 * 1000;
})();
const setAdminAuthCookie = (res, adminUser) => {
  try {
    const exp = Date.now() + ADMIN_AUTH_TTL_MS;
    const token = signAdminAuth({ username: String(adminUser.username || ''), role: String(adminUser.role || ''), exp });
    // SEM sameSite de propósito: igual ao connect.sid (que comprovadamente sobrevive no navegador
    // do usuário). Cookies marcados SameSite=Lax estavam sendo descartados (extensão/AV/config),
    // derrubando o login. Sem o atributo, o cookie de admin persiste e re-autentica sozinho.
    res.cookie(ADMIN_AUTH_COOKIE, token, { httpOnly: true, secure: false, path: '/', maxAge: ADMIN_AUTH_TTL_MS });
  } catch (_) {}
};
const clearAdminAuthCookie = (res) => {
  try { res.clearCookie(ADMIN_AUTH_COOKIE, { path: '/' }); } catch (_) {}
};

const recoveryLinkSecret = () => String(process.env.RECOVERY_LINK_SECRET || process.env.ADMIN_COOKIE_SECRET || "agencia-oppus-secret-key");
const signRecoveryToken = (payloadObj) => {
  const json = JSON.stringify(payloadObj || {});
  const payload = base64UrlEnc(Buffer.from(json, 'utf8'));
  const sig = base64UrlEnc(crypto.createHmac('sha256', recoveryLinkSecret()).update(payload).digest());
  return `${payload}.${sig}`;
};
const verifyRecoveryToken = (token) => {
  try {
    const t = String(token || '');
    const idx = t.lastIndexOf('.');
    if (idx < 1) return null;
    const payload = t.slice(0, idx);
    const sig = t.slice(idx + 1);
    const expected = base64UrlEnc(crypto.createHmac('sha256', recoveryLinkSecret()).update(payload).digest());
    const a = Buffer.from(String(sig), 'utf8');
    const b = Buffer.from(String(expected), 'utf8');
    if (a.length !== b.length) return null;
    if (!crypto.timingSafeEqual(a, b)) return null;
    const obj = JSON.parse(base64UrlDec(payload).toString('utf8'));
    if (obj && obj.exp && Number(obj.exp) > 0 && Date.now() > Number(obj.exp)) return null;
    return obj || null;
  } catch (_) {
    return null;
  }
};

// DIAGNÓSTICO de login: grava num arquivo (auth-debug.log) p/ inspeção posterior, já que o
// terminal do usuário não é visível. Volume baixo (só rotas admin). Remover depois de resolver.
const __authDbgFile = path.join(__dirname, 'auth-debug.log');
function __authDbg(line) {
  try { fs.appendFileSync(__authDbgFile, '[' + new Date().toISOString() + '] ' + line + '\n'); } catch (_) {}
}
function __cookieSnapshot(req) {
  const raw = String((req && req.headers && req.headers.cookie) || '');
  const hasSid = /(?:^|;\s*)connect\.sid=/.test(raw);
  const hasAdmin = new RegExp('(?:^|;\\s*)' + ADMIN_AUTH_COOKIE + '=').test(raw);
  const host = String((req && req.headers && req.headers.host) || '');
  const ref = String((req && req.headers && req.headers.referer) || '');
  let refHost = '';
  try { refHost = ref ? new URL(ref).host : ''; } catch (_) {}
  return 'cookieSid=' + hasSid + ' cookieAdmin=' + hasAdmin + ' cookieLen=' + raw.length + ' HOST=' + host + (refHost && refHost !== host ? (' REF=' + refHost) : '');
}

// Middleware de autenticação Admin
const requireAdmin = (req, res, next) => {
    const __isNav = !!(req.headers.accept && req.headers.accept.indexOf('html') > -1); // navegação (não XHR/poller)
    if (req.session && req.session.adminUser) {
      try { setAdminAuthCookie(res, req.session.adminUser); } catch (_) {} // renova janela (sliding) → usuário ativo não desloga
      if (__isNav) __authDbg('PASS(session) ' + req.method + ' ' + (req.originalUrl || req.url) + ' user=' + (req.session.adminUser.username || '?') + ' ' + __cookieSnapshot(req));
      return next();
    }
    try {
      const cookies = parseCookieHeader(req);
      const token = cookies[ADMIN_AUTH_COOKIE] || '';
      const data = verifyAdminAuth(token);
      if (data && data.username) {
        req.session.adminUser = { username: data.username, role: data.role || '' };
        try { setAdminAuthCookie(res, req.session.adminUser); } catch (_) {} // reemite o cookie c/ prazo novo
        if (__isNav) __authDbg('PASS(cookie) ' + req.method + ' ' + (req.originalUrl || req.url) + ' user=' + data.username + ' ' + __cookieSnapshot(req));
        try { req.session.save(() => next()); } catch (_) { return next(); }
        return;
      }
    } catch (_) {}
    // DIAGNÓSTICO (logout em ~2min relatado): loga EXATAMENTE por que caiu no /login.
    try {
      const ck = parseCookieHeader(req);
      const tok = ck[ADMIN_AUTH_COOKIE] || '';
      let why = tok ? 'unknown' : 'sem_cookie_admin';
      if (tok) {
        const idx = tok.lastIndexOf('.');
        if (idx < 1) why = 'token_malformado';
        else {
          try {
            const payload = tok.slice(0, idx);
            const expected = base64UrlEnc(crypto.createHmac('sha256', adminAuthSecret()).update(payload).digest());
            if (expected !== tok.slice(idx + 1)) why = 'assinatura_invalida(secret_mudou?)';
            else {
              const obj = JSON.parse(base64UrlDec(payload).toString('utf8'));
              if (obj && obj.exp && Date.now() > Number(obj.exp)) why = 'expirado_ha_' + Math.round((Date.now() - Number(obj.exp)) / 1000) + 's';
              else if (!obj || !obj.username) why = 'sem_username_no_token';
              else why = 'verificou_ok_mas_caiu(?)';
            }
          } catch (e) { why = 'erro_decode'; }
        }
      }
      const msg = '🚪 FAIL -> /login | ' + req.method + ' ' + (req.originalUrl || req.url) +
        ' | sessao=' + (!!req.session) + ' adminUser=' + (!!(req.session && req.session.adminUser)) +
        ' ' + __cookieSnapshot(req) + ' motivo=' + why;
      console.warn(msg);
      __authDbg(msg);
    } catch (_) {}
    if (req.xhr || (req.headers.accept && req.headers.accept.indexOf('json') > -1)) {
        return res.status(401).json({ error: 'Unauthorized' });
    }
    return res.redirect('/login');
};

const onlinePresence = new Map();
const onlinePresenceTtlMs = 45 * 1000;
const pageViewDedupe = new Map();
const pageViewDedupeTtlMs = 30 * 60 * 1000;
const geoCache = new Map();
