const maybeSendRefil2ToolEmail = async (record, col, req) => {
    try {
        if (!record || !col || !record._id) return;
        if (record?.manualSale?.source === 'whatsapp' && record?.manualSale?.skipEmails === true) return;
        const customer = (record && record.customer && typeof record.customer === 'object') ? record.customer : {};
        const to = String(customer.email || '').trim();
        if (!to) return;

        const isPaid = (function () {
            const st = String(record.status || '').toLowerCase();
            const wst = String(record?.woovi?.status || '').toLowerCase();
            if (st === 'pago' || wst === 'pago') return true;
            if (record?.paidAt || record?.woovi?.paidAt || record?.payment?.paidAt) return true;
            const xst = String(record?.expay?.status || '').toLowerCase();
            if (xst === 'pago' || xst === 'paid' || xst === 'completed') return true;
            const efiSt = String(record?.efi?.status || '').toLowerCase();
            if (efiSt === 'paid' || efiSt === 'settled') return true;
            const pgSt = String(record?.pagarme?.status || '').toLowerCase();
            if (/(paid|settled|captured|authorized|succeeded|aprovado|confirmado)/i.test(pgSt)) return true;
            const phSt = String(record?.paghiper?.status || '').toLowerCase();
            if (phSt === 'pago' || phSt === 'paid' || phSt === 'completed') return true;
            return false;
        })();
        if (!isPaid) return;

        const isEligible = (function () {
            try {
                const buildMapFromArr = (arr) => (Array.isArray(arr) ? arr : []).reduce((acc, it) => { const k = String(it?.key || '').trim(); if (k) acc[k] = String(it?.value ?? '').trim(); return acc; }, {});
                const mapPaid = (record && record.additionalInfoMapPaid && typeof record.additionalInfoMapPaid === 'object') ? record.additionalInfoMapPaid : buildMapFromArr(record?.additionalInfoPaid);
                const mapOrig = (record && record.additionalInfoMap && typeof record.additionalInfoMap === 'object') ? record.additionalInfoMap : buildMapFromArr(record?.additionalInfo);
                const map = Object.assign({}, mapOrig, mapPaid);
                const tipoServicoRaw = String(map['tipo_servico'] || record?.tipoServico || record?.tipo || '').toLowerCase().trim();
                const categoriaServicoRaw = String(map['categoria_servico'] || record?.categoriaServico || '').toLowerCase().trim();
                const isSeguidores = !categoriaServicoRaw || categoriaServicoRaw.includes('seguidores');
                const isOkTipo = tipoServicoRaw.includes('mistos') || tipoServicoRaw.includes('brasileir');
                return isSeguidores && isOkTipo;
            } catch (_) {
                return false;
            }
        })();
        if (!isEligible) return;

        if (record?.emails?.refil2ToolSentAt) return;

        const nowIso = new Date().toISOString();
        const lockFilter = {
            _id: record._id,
            $and: [
                { $or: [{ 'emails.refil2ToolSentAt': { $exists: false } }, { 'emails.refil2ToolSentAt': null }, { 'emails.refil2ToolSentAt': '' }] },
                { $or: [{ 'emails.refil2ToolLockAt': { $exists: false } }, { 'emails.refil2ToolLockAt': null }, { 'emails.refil2ToolLockAt': '' }] }
            ]
        };
        const lockRes = await col.updateOne(lockFilter, { $set: { 'emails.refil2ToolLockAt': nowIso } });
        if (!lockRes || !lockRes.matchedCount) return;

        try {
            const reqSafe = req || { ip: '', connection: {}, headers: {}, get: () => '' };
            const linkRec = await ensureRefilLink(record?.identifier, record?.correlationID, reqSafe);
            const token = String(linkRec?.id || '').trim();
            if (!token) throw new Error('refil_token_missing');

            await sendRefil2ToolEmailToCustomer({ record, token });
            await col.updateOne(
                { _id: record._id, 'emails.refil2ToolLockAt': nowIso },
                { $set: { 'emails.refil2ToolSentAt': new Date().toISOString() }, $unset: { 'emails.refil2ToolLockAt': '' } }
            );
        } catch (e) {
            try {
                await col.updateOne({ _id: record._id, 'emails.refil2ToolLockAt': nowIso }, { $unset: { 'emails.refil2ToolLockAt': '' }, $set: { 'emails.refil2ToolLastError': String(e?.message || e) } });
            } catch (_) {}
        }
    } catch (_) {}
};

const pruneOnlinePresence = () => {
    const now = Date.now();
    for (const [k, v] of onlinePresence.entries()) {
        if (!v || typeof v.lastSeen !== 'number' || (now - v.lastSeen) > onlinePresenceTtlMs) {
            onlinePresence.delete(k);
        }
    }
};

const prunePageViewDedupe = () => {
    const now = Date.now();
    for (const [k, ts] of pageViewDedupe.entries()) {
        if (!Number.isFinite(Number(ts)) || (now - Number(ts)) > pageViewDedupeTtlMs) {
            pageViewDedupe.delete(k);
        }
    }
};

const updateOnlinePresence = (clientId, path) => {
    const id = String(clientId || '').trim();
    if (!id) return;
    const p = String(path || '').trim();
    onlinePresence.set(id, { lastSeen: Date.now(), path: p });
};

const readJsonBody = (req) => new Promise((resolve) => {
    try {
        if (!req) return resolve({});
        let raw = '';
        req.setEncoding('utf8');
        req.on('data', (chunk) => {
            raw += String(chunk || '');
            if (raw.length > 4096) {
                try { req.destroy(); } catch (_) {}
                resolve({});
            }
        });
        req.on('end', () => {
            try {
                const t = String(raw || '').trim();
                if (!t) return resolve({});
                resolve(JSON.parse(t));
            } catch (_) {
                resolve({});
            }
        });
        req.on('error', () => resolve({}));
    } catch (_) {
        resolve({});
    }
});

const insertPageViewIfNeeded = (clientId, path, req) => {
    try {
        prunePageViewDedupe();
        const cid = String(clientId || '').trim();
        const p = String(path || '').trim();
        if (!cid || !p) return;
        const key = `${cid}|${p}`;
        const now = Date.now();
        const last = Number(pageViewDedupe.get(key) || 0);
        if (Number.isFinite(last) && last > 0 && (now - last) < pageViewDedupeTtlMs) return;
        pageViewDedupe.set(key, now);
        const ip = String((req && (req.realIP || req.ip)) || '').trim();
        const ua = String((req && req.headers && req.headers['user-agent']) || '').trim();
        const ref = String((req && ((req.get && req.get('Referer')) || (req.headers && req.headers['referer']))) || '').trim();
        (async () => {
            try {
                const { getCollection } = require('./mongodbClient');
                const col = await getCollection('page_views');
                if (!col || typeof col.insertOne !== 'function') return;
                let geo = null;
                try {
                    const geoPromise = geoLookupIp(ip);
                    const timeout = new Promise((resolve) => setTimeout(() => resolve(null), 1200));
                    geo = await Promise.race([geoPromise, timeout]);
                } catch (_) { geo = null; }
                const doc = { path: p, clientId: cid, ip, ua, createdAt: new Date() };
                if (ref) doc.referer = ref;
                if (geo && (geo.city || geo.region || geo.country)) {
                    doc.city = geo.city || '';
                    doc.region = geo.region || '';
                    doc.country = geo.country || '';
                    if (typeof geo.lat === 'number') doc.lat = geo.lat;
                    if (typeof geo.lon === 'number') doc.lon = geo.lon;
                    doc.geoSource = geo.source || '';
                }
                await col.insertOne(doc);
            } catch (_) {}
        })();
    } catch (_) {}
};

app.post('/api/online/ping', async (req, res) => {
    try {
        pruneOnlinePresence();
        prunePageViewDedupe();
        let body = (req && req.body && typeof req.body === 'object') ? req.body : null;
        if (!body || typeof body !== 'object') {
            const ct = String((req && req.headers && req.headers['content-type']) || '').toLowerCase();
            if (ct.includes('application/json')) {
                body = await readJsonBody(req);
            }
        }
        body = (body && typeof body === 'object') ? body : {};
        const cid = String((req && req.oppusClientId) || getCookieValue(req, OPPUS_CLIENT_ID_COOKIE) || body.clientId || '').trim();
        updateOnlinePresence(cid, body.path);
    } catch (_) {}
    return res.json({ ok: true });
});

app.get('/api/online/stats', requireAdmin, (req, res) => {
    try {
        pruneOnlinePresence();
        const now = Date.now();
        let total = 0;
        const byPath = {};
        for (const v of onlinePresence.values()) {
            if (!v || typeof v.lastSeen !== 'number' || (now - v.lastSeen) > onlinePresenceTtlMs) continue;
            total += 1;
            const p = String(v.path || '').trim() || '/';
            byPath[p] = (byPath[p] || 0) + 1;
        }
        return res.json({ online: total, byPath });
    } catch (e) {
        return res.json({ online: 0, byPath: {} });
    }
});

// Helper: Hash password (SHA-256)
function hashPassword(password) {
    return crypto.createHash('sha256').update(password).digest('hex');
}

function normalizeProviderResponseData(data) {
    if (!data) return {};
    if (typeof data === 'object') return data;
    if (typeof data === 'string') {
        const t = data.trim();
        if (!t) return {};
        try { return JSON.parse(t); } catch (_) { return { raw: data }; }
    }
    return { raw: data };
}

function extractProviderOrderId(data) {
    const d = normalizeProviderResponseData(data);
    const candidates = [
        d.order, d.id, d.order_id, d.orderId,
        d.data && d.data.order, d.data && d.data.id, d.data && d.data.order_id, d.data && d.data.orderId,
        d.result && d.result.order, d.result && d.result.id, d.result && d.result.order_id, d.result && d.result.orderId,
        d.response && d.response.order, d.response && d.response.id, d.response && d.response.order_id, d.response && d.response.orderId
    ];
    for (const v of candidates) {
        if (typeof v === 'number' && Number.isFinite(v) && v > 0) return String(v);
        if (typeof v === 'string') {
            const t = v.trim();
            if (t && t.toLowerCase() !== 'unknown' && t.toLowerCase() !== 'null' && t.toLowerCase() !== 'undefined') return t;
        }
    }
    return null;
}

async function findExistingFamaOrderIdByLink(col, link) {
    try {
        const l = String(link || '').trim();
        if (!l || !col) return null;
        const doc = await col.findOne(
            {
                $or: [
                    { 'fama24h.requestPayload.link': l, 'fama24h.orderId': { $exists: true, $ne: null } },
                    { 'fama24h_multi.orders': { $elemMatch: { link: l, orderId: { $exists: true, $ne: null } } } },
                    { 'fama24h_multi.orders': { $elemMatch: { link: l, id: { $exists: true, $ne: null } } } }
                ]
            },
            { projection: { 'fama24h.orderId': 1, 'fama24h.requestPayload.link': 1, 'fama24h_multi.orders': 1, paidAt: 1, createdAt: 1 }, sort: { paidAt: -1, createdAt: -1 } }
        );
        if (!doc) return null;
        const directLink = doc?.fama24h?.requestPayload?.link;
        if (directLink === l && doc?.fama24h?.orderId !== null && doc?.fama24h?.orderId !== undefined) {
            const v = String(doc.fama24h.orderId).trim();
            return v ? v : null;
        }
        const arr = (doc && doc.fama24h_multi && Array.isArray(doc.fama24h_multi.orders)) ? doc.fama24h_multi.orders : [];
        for (const it of arr) {
            if (!it || String(it.link || '').trim() !== l) continue;
            const oid = it.orderId ?? it.id ?? null;
            if (oid !== null && oid !== undefined) {
                const v = String(oid).trim();
                if (v) return v;
            }
        }
        return null;
    } catch (_) {
        return null;
    }
}

async function postFormWithRetry(url, formBodyString, timeoutMs, maxAttempts, axiosOptions) {
    const sleep = (ms) => new Promise(r => setTimeout(r, ms));
    let lastErr = null;
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
        try {
            const baseOpts = { headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, timeout: timeoutMs };
            const opts = Object.assign({}, baseOpts, (axiosOptions && typeof axiosOptions === 'object') ? axiosOptions : {});
            opts.headers = Object.assign({}, baseOpts.headers, (opts.headers && typeof opts.headers === 'object') ? opts.headers : {});
            return await axios.post(url, formBodyString, opts);
        } catch (err) {
            lastErr = err;
            const msg = String(err?.message || '').toLowerCase();
            const code = String(err?.code || '').toLowerCase();
            const status = err?.response?.status || 0;
            const isTimeout = msg.includes('timeout') || code === 'ecconnaborted';
            const isRetryable = isTimeout || !status || status >= 500;
            if (attempt < maxAttempts && isRetryable) {
                await sleep(1200 * attempt);
                continue;
            }
            throw err;
        }
    }
    throw lastErr || new Error('request_failed');
}

// Despacha o bump de CURTIDAS REAIS para o TopFama (mesma API SMM do fornecedor_social).
// Grava no campo `topfama_likes`, com lock anti-duplicidade (status processing/created).
// Usado pelos vários caminhos de fulfillment (principal, retry, mark-paid, recovery).
async function dispatchTopfamaLikesBump(col, filter, serviceId, link, quantity) {
    try {
        const keyTop = process.env.TOPFAMA_API_KEY || '';
        if (!keyTop) {
            await col.updateOne(filter, { $set: { 'topfama_likes.status': 'missing_key', 'topfama_likes.error': { code: 'missing_api_key', env: 'TOPFAMA_API_KEY' }, 'topfama_likes.requestPayload': { service: serviceId, link: String(link || ''), quantity }, 'topfama_likes.requestedAt': new Date().toISOString() } });
            return;
        }
        const lock = await col.updateOne(
            { ...filter, 'topfama_likes.orderId': { $exists: false }, 'topfama_likes.status': { $nin: ['processing', 'created'] } },
            { $set: { 'topfama_likes.status': 'processing', 'topfama_likes.requestPayload': { service: serviceId, link, quantity }, 'topfama_likes.requestedAt': new Date().toISOString() }, $unset: { 'topfama_likes.error': '' } }
        );
        if (lock.modifiedCount <= 0) return;
        const payload = new URLSearchParams({ key: String(keyTop), action: 'add', service: String(serviceId), link: String(link), quantity: String(quantity) });
        try { console.log('🚀 sending_topfama_likes', { service: serviceId, link, quantity }); } catch (_) {}
        try {
            const resp = await postFormWithRetry('https://topfama.com/api/v2', payload.toString(), 60000, 3);
            const data = normalizeProviderResponseData(resp.data);
            const orderId = extractProviderOrderId(data);
            const provErr = (data && (data.error || (data.data && data.data.error) || (data.response && data.response.error))) || null;
            if (provErr && !orderId) {
                const errStr = typeof provErr === 'string' ? provErr : JSON.stringify(provErr);
                const st = errStr && errStr.includes('link_duplicate') ? 'duplicate' : 'error';
                const setObj = { 'topfama_likes.status': st, 'topfama_likes.requestPayload': { service: serviceId, link, quantity }, 'topfama_likes.response': data, 'topfama_likes.requestedAt': new Date().toISOString() };
                setObj[st === 'duplicate' ? 'topfama_likes.duplicate' : 'topfama_likes.error'] = provErr;
                if (st === 'duplicate') await col.updateOne(filter, { $set: setObj, $unset: { 'topfama_likes.error': '' } });
                else await col.updateOne(filter, { $set: setObj });
            } else {
                const setObj = { 'topfama_likes.status': orderId ? 'created' : 'unknown', 'topfama_likes.requestPayload': { service: serviceId, link, quantity }, 'topfama_likes.response': data, 'topfama_likes.requestedAt': new Date().toISOString() };
                if (orderId) setObj['topfama_likes.orderId'] = orderId;
                await col.updateOne(filter, { $set: setObj, $unset: { 'topfama_likes.error': '', 'topfama_likes.duplicate': '' } });
            }
        } catch (e) {
            try { console.error('❌ topfama_likes_error', e?.response?.data || e?.message || String(e), { link, quantity }); } catch (_) {}
            const errVal = e?.response?.data || e?.message || String(e);
            const errStr = (typeof errVal === 'string') ? errVal : JSON.stringify(errVal);
            const st = errStr && errStr.includes('link_duplicate') ? 'duplicate' : 'error';
            const setObj = { 'topfama_likes.status': st, 'topfama_likes.requestPayload': { service: serviceId, link, quantity }, 'topfama_likes.requestedAt': new Date().toISOString() };
            setObj[st === 'duplicate' ? 'topfama_likes.duplicate' : 'topfama_likes.error'] = errVal;
            if (st === 'duplicate') await col.updateOne(filter, { $set: setObj, $unset: { 'topfama_likes.error': '' } });
            else await col.updateOne(filter, { $set: setObj });
        }
    } catch (_) {}
}

