// Função para baixar e servir imagem localmente
async function downloadAndServeImage(imageUrl, username, httpsAgent = null) {
  try {
    // Criar pasta de cache se não existir
    const cacheDir = path.join(__dirname, 'temp_images');
    if (!fs.existsSync(cacheDir)) {
      fs.mkdirSync(cacheDir, { recursive: true });
    }
    
    // Nome do arquivo local
    const fileName = `${username}_${Date.now()}.jpg`;
    const filePath = path.join(cacheDir, fileName);
    
    // Baixar imagem
    const response = await axios.get(imageUrl, {
      responseType: 'arraybuffer',
      timeout: 10000,
      httpsAgent: httpsAgent || undefined
    });
    
    // Salvar localmente
    fs.writeFileSync(filePath, response.data);
    
    // Agendar exclusão após 5 minutos
    setTimeout(() => {
      try {
        if (fs.existsSync(filePath)) {
          fs.unlinkSync(filePath);
          console.log(`🗑️ Imagem local excluída: ${fileName}`);
        }
      } catch (err) {
        console.error('Erro ao excluir imagem local:', err.message);
      }
    }, 5 * 60 * 1000); // 5 minutos
    
    return `/temp-images/${fileName}`;
  } catch (error) {
    console.error('Erro ao baixar imagem:', error.message);
    return null;
  }
}

// Função utilitária para gerar fingerprint
function generateFingerprint(ip, userAgent) {
    return crypto.createHash('md5').update(ip + '|' + userAgent).digest('hex');
}

function normalizeEmail(v) {
    return String(v || '').trim().toLowerCase();
}

function hashPasswordScrypt(password) {
    const pwd = String(password || '');
    const salt = crypto.randomBytes(16);
    const key = crypto.scryptSync(pwd, salt, 64, { N: 16384, r: 8, p: 1 });
    return `scrypt$${salt.toString('base64')}$${key.toString('base64')}`;
}

function verifyPasswordScrypt(password, stored) {
    try {
        const s = String(stored || '');
        if (!s.startsWith('scrypt$')) return false;
        const parts = s.split('$');
        const saltB64 = parts[1] || '';
        const hashB64 = parts[2] || '';
        const salt = Buffer.from(saltB64, 'base64');
        const expected = Buffer.from(hashB64, 'base64');
        if (!salt.length || !expected.length) return false;
        const key = crypto.scryptSync(String(password || ''), salt, expected.length, { N: 16384, r: 8, p: 1 });
        return crypto.timingSafeEqual(expected, key);
    } catch (_) {
        return false;
    }
}

function generateTempPassword() {
    const raw = crypto.randomBytes(12).toString('base64');
    return raw.replace(/[^a-zA-Z0-9]/g, '').slice(0, 12);
}

function sha256Hex(v) {
    return crypto.createHash('sha256').update(String(v || '')).digest('hex');
}

