            if (!m) return '';
            const kind = String(m[2] || '').toLowerCase();
            let code = String(m[3] || '');
            if (!kind || !code) return '';
            if (code.length > 15) code = code.slice(0, 11);
            return `https://www.instagram.com/${kind}/${encodeURIComponent(code)}/`;
