// Busca posts via RocketAPI. RÁPIDO: se já temos o ID do IG salvo, vai DIRETO no get_media
// (pula get_info/search). Senão resolve por get_info (timeout curto) → search e SALVA o ID p/ as próximas.
async function fetchInstagramPostsRocketApi(username, opts) {
  const reels = !!(opts && opts.reels); // modo reels (visualizações) → usa get_clips
  const uname = String(username || '').trim().replace(/^@+/, '').toLowerCase();
  if (!uname) return { success: false, error: 'missing_username' };
  if (!process.env.ROCKETAPI_TOKEN) return { success: false, error: 'no_token' };
  const auth = { headers: { 'Authorization': `Token ${process.env.ROCKETAPI_TOKEN}` }, validateStatus: () => true };

  const mapMediaItems = (items) => (Array.isArray(items) ? items : []).map(item => ({
    shortcode: item.code,
    takenAt: item.taken_at,
    isVideo: item.media_type === 2 || !!item.video_versions,
    displayUrl: (item.image_versions2 && item.image_versions2.candidates && item.image_versions2.candidates[0]) ? item.image_versions2.candidates[0].url : null,
    videoUrl: (item.video_versions && item.video_versions[0]) ? item.video_versions[0].url : null,
    typename: item.media_type === 2 ? 'GraphVideo' : 'GraphImage'
  })).filter(p => p.shortcode).slice(0, 12);
  const getMediaById = async (id) => {
    try {
      const media = await axios.post('https://v1.rocketapi.io/instagram/user/get_media', { id: String(id), count: 12 }, Object.assign({}, auth, { timeout: 7000 }));
      if (media.status !== 200) return [];
      const items = (media.data && media.data.response && media.data.response.body && media.data.response.body.items) ? media.data.response.body.items : [];
      return mapMediaItems(items);
    } catch (_) { return []; }
  };
  // REELS (visualizações): get_clips — cada item vem como { media: {...} }.
  const getClipsById = async (id) => {
    try {
      const r = await axios.post('https://v1.rocketapi.io/instagram/user/get_clips', { id: String(id), count: 12 }, Object.assign({}, auth, { timeout: 8000 }));
      if (r.status !== 200) return [];
      const items = (r.data && r.data.response && r.data.response.body && r.data.response.body.items) ? r.data.response.body.items : [];
      return (Array.isArray(items) ? items : []).map(w => {
        const m = (w && w.media) ? w.media : w;
        if (!m || !m.code) return null;
        return {
          shortcode: m.code,
          takenAt: m.taken_at,
          isVideo: true,
          displayUrl: (m.image_versions2 && m.image_versions2.candidates && m.image_versions2.candidates[0]) ? m.image_versions2.candidates[0].url : null,
          videoUrl: (m.video_versions && m.video_versions[0]) ? m.video_versions[0].url : null,
          typename: 'GraphVideo'
        };
      }).filter(Boolean).slice(0, 12);
    } catch (_) { return []; }
  };
  const getMedia = reels ? getClipsById : getMediaById;
  const persistId = async (id) => {
    try { const vu = await getCollection('validated_insta_users'); await vu.updateOne({ username: uname }, { $set: { igUserId: String(id) } }); } catch (_) {}
  };

  // 0) ID já salvo → get_media DIRETO (pula get_info/search) = caminho rápido.
  try {
    const vu0 = await getCollection('validated_insta_users');
    const d0 = await vu0.findOne({ username: uname }, { projection: { igUserId: 1 } });
    const sid = (d0 && d0.igUserId) ? String(d0.igUserId) : '';
    if (sid) {
      const posts = await getMedia(sid);
      if (posts.length) return { success: true, username: uname, posts, via: 'stored_id' };
    }
  } catch (_) {}

  let posts = [];
  let userId = null;
  let isPrivate = false;
  let resolvedUsername = uname;

  // 1) get_info (timeout curto — é o gargalo e muitas contas voltam vazias). Pode já trazer edges.
  try {
    const info = await axios.post('https://v1.rocketapi.io/instagram/user/get_info', { username: uname }, Object.assign({}, auth, { timeout: 5000 }));
    if (info.status === 200) {
      global.rocketApiDisabledUntil = 0;
      const rUser = (info.data && info.data.response && info.data.response.body && info.data.response.body.data && info.data.response.body.data.user) ? info.data.response.body.data.user : null;
      if (rUser) {
        userId = rUser.id || null;
        isPrivate = !!rUser.is_private;
        resolvedUsername = rUser.username || uname;
        const edges = (rUser.edge_owner_to_timeline_media && Array.isArray(rUser.edge_owner_to_timeline_media.edges)) ? rUser.edge_owner_to_timeline_media.edges : [];
        if (!reels && edges.length) {
          posts = edges.map(e => (e && e.node) ? ({
            shortcode: e.node.shortcode, takenAt: e.node.taken_at_timestamp, isVideo: !!e.node.is_video,
            displayUrl: e.node.display_url || e.node.thumbnail_src || null, videoUrl: e.node.video_url || null, typename: e.node.__typename || ''
          }) : null).filter(Boolean).slice(0, 12);
        }
      }
    }
  } catch (_) {}

  // 2) get_info vazio → SEARCH (match EXATO do @) p/ achar o ID.
  if (!userId) {
    try {
      const s = await axios.post('https://v1.rocketapi.io/instagram/search', { query: uname }, Object.assign({}, auth, { timeout: 7000 }));
      const body = s.data && s.data.response && s.data.response.body;
      const users = (body && (body.users || (body.data && body.data.users))) || [];
      const exact = (Array.isArray(users) ? users : []).map(x => (x && x.user) ? x.user : x).find(u => u && String(u.username || '').toLowerCase() === uname);
      if (exact) { userId = exact.pk || exact.id || null; isPrivate = !!exact.is_private; }
    } catch (_) {}
  }

  // 3) get_media/get_clips pelo ID resolvido.
  if (!posts.length && userId && !isPrivate) {
    posts = await getMedia(userId);
  }

  if (userId) { await persistId(userId); } // salva p/ deixar as próximas buscas rápidas

  if (posts.length) return { success: true, username: resolvedUsername, posts };
  return { success: false, error: userId ? 'rocket_no_posts' : 'rocket_user_not_found', isPrivate: !!isPrivate };
}

app.get('/api/instagram/posts', async (req, res) => {
  try {
    try { res.set('Cache-Control', 'no-store'); } catch (_) {}
    const tk = String(req.get('x-oppus-api-tk') || req.query.tk || '').trim();
    const sessTk = req.session && req.session.oppusApiTk ? String(req.session.oppusApiTk) : '';
    if (!sessTk || !tk || tk !== sessTk) {
      return res.status(403).json({ success: false, error: 'forbidden', posts: [] });
    }
    const ipRL = req.realIP || req.ip || req.connection.remoteAddress || '';
    if (hitRateLimit(`ig_posts_ip:${ipRL}`, 60, 10 * 60 * 1000)) {
      return res.status(429).json({ success: false, error: 'rate_limited', posts: [] });
    }
    const usernameParam = String(req.query.username || '').trim();
    const usernameSession = req.session && req.session.instagramProfile && req.session.instagramProfile.username ? String(req.session.instagramProfile.username) : '';
    const username = String(usernameParam || usernameSession || '').trim().toLowerCase();
    if (!username) return res.json({ success: false, error: 'missing_username', posts: [] });
    const debugInsert = String(req.query.debug || '').trim() === '1';
    let debugInfo = null;

    // ── Modo REELS (visualizações): busca os reels do perfil (get_clips), não o feed ──
    const wantReels = String(req.query.reels || req.query.type || '').trim().toLowerCase() === '1' || String(req.query.reels || req.query.type || '').trim().toLowerCase() === 'reels';
    if (wantReels) {
      // 1) cache de reels (<1h)
      try {
        const vu = await getCollection('validated_insta_users');
        const cd = await vu.findOne({ username }, { projection: { latestReels: 1, reelsCheckedAt: 1 } });
        if (cd && Array.isArray(cd.latestReels) && cd.latestReels.length) {
          const fresh = cd.reelsCheckedAt && (Date.now() - new Date(cd.reelsCheckedAt).getTime() < 3600000);
          if (fresh) { console.log('[API] Retornando REELS do cache'); return res.json({ success: true, username, posts: cd.latestReels, source: 'cache_reels' }); }
        }
      } catch (_) {}
      // 2) RocketAPI get_clips
      try {
        console.log('[API] tentando RocketAPI (reels/get_clips)');
        const rk = await fetchInstagramPostsRocketApi(username, { reels: true });
        if (rk && rk.success && Array.isArray(rk.posts) && rk.posts.length) {
          console.log(`✅ RocketAPI trouxe ${rk.posts.length} reels para @${username}`);
          try { const vu = await getCollection('validated_insta_users'); await vu.updateOne({ username }, { $set: { latestReels: rk.posts, reelsCheckedAt: new Date().toISOString() } }); } catch (_) {}
          return res.json({ success: true, username, posts: rk.posts, source: 'rocketapi_clips' });
        }
        console.log('[API] RocketAPI reels sem resultado:', (rk && rk.error) || 'desconhecido');
      } catch (e) { console.log('[API] RocketAPI reels erro:', e && e.message); }
      // 3) cookies (feed) filtrando só vídeos
      try {
        const result = await fetchInstagramRecentPosts(username);
        if (result && result.success && Array.isArray(result.posts)) {
          const vids = result.posts.filter(p => p && (p.isVideo || p.videoUrl));
          if (vids.length) {
            try { const vu = await getCollection('validated_insta_users'); await vu.updateOne({ username }, { $set: { latestReels: vids, reelsCheckedAt: new Date().toISOString() } }); } catch (_) {}
            return res.json({ success: true, username, posts: vids, source: 'cookies_reels' });
          }
        }
      } catch (_) {}
      // 4) último recurso: reels salvos (mesmo velhos) → embed renderiza pelo shortcode
      try {
        const vu = await getCollection('validated_insta_users');
        const cd = await vu.findOne({ username }, { projection: { latestReels: 1 } });
        if (cd && Array.isArray(cd.latestReels) && cd.latestReels.length) return res.json({ success: true, username, posts: cd.latestReels, stale: true });
      } catch (_) {}
      return res.json({ success: true, username, posts: [] });
    }

    try {
      const vu = await getCollection('validated_insta_users');
      // Tentar buscar do banco primeiro se tiver posts recentes (ex: < 1h)
      // Se acabou de validar o perfil, os posts estarão lá
      const cachedDoc = await vu.findOne({ username });
      if (cachedDoc && cachedDoc.latestPosts && Array.isArray(cachedDoc.latestPosts) && cachedDoc.latestPosts.length > 0) {
          // Frescor dos POSTS = quando os posts foram REALMENTE capturados (lastPostsAt).
          // NÃO usar checkedAt: o check de privacidade (check_privacy_rocketapi) bumpa o checkedAt
          // sem atualizar latestPosts, o que fazia uma lista de posts velha parecer fresca e
          // esconder posts novos (ex.: perfil com 2 posts mostrando só 1).
          const lastCheck = cachedDoc.lastPostsAt;
          const isFresh = lastCheck && (Date.now() - new Date(lastCheck).getTime() < 3600000); // 1h
          
          if (isFresh && cachedDoc.latestPosts.length >= 1) {
               console.log('[API] Retornando posts do banco (validated_insta_users)');
               return res.json({ success: true, username, posts: cachedDoc.latestPosts });
          }
      }

      // NÃO setar lastPostsAt aqui (antes de capturar posts) — senão marca como "fresco" sem ter
      // posts novos. lastPostsAt só é atualizado quando os posts são de fato buscados (abaixo).
      const doc = { source: 'api.instagram.posts', lastPostsAttemptAt: new Date().toISOString() };
      // Remove username from $setOnInsert to avoid conflict if it's already in the filter
      await vu.updateOne({ username }, { $setOnInsert: { firstSeenAt: new Date().toISOString() }, $set: doc }, { upsert: true });
      debugInfo = { ok: true, username };
      try { console.log('🗃️ Posts route: upsert ok', debugInfo); } catch(_) {}
    } catch (err) { debugInfo = { ok: false, error: err?.message || String(err) }; try { console.error('❌ Posts route: upsert error', err?.message || String(err)); } catch(_) {} }
    
    // 1) Cookies via web_profile_info (rápido ~1-2s e confiável p/ qualquer conta existente).
    //    O fetch já tenta DIRETO (sem proxy) quando o proxy falha com 407. É mais rápido que a
    //    RocketAPI nas contas de cliente (onde o get_info dela volta vazio e precisa de search).
    try {
      console.log('[API] tentando web_profile_info com cookies');
      const result = await fetchInstagramRecentPosts(username);
      if (result && result.success && Array.isArray(result.posts) && result.posts.length) {
        try {
          const vu2 = await getCollection('validated_insta_users');
          await vu2.updateOne(
            { username },
            { $set: { latestPosts: result.posts, lastPostsAt: new Date().toISOString() } }
          );
        } catch (_) {}
        if (debugInsert) return res.json(Object.assign({}, result, { debugInsert: debugInfo }));
        return res.json(result);
      }
    } catch (e) { /* fallback abaixo */ }

    // 2) RocketAPI (reserva). Usa ID salvo p/ get_media direto quando possível.
    try {
      console.log('[API] tentando RocketAPI (posts)');
      const rk = await fetchInstagramPostsRocketApi(username);
      if (rk && rk.success && Array.isArray(rk.posts) && rk.posts.length) {
        console.log(`✅ RocketAPI trouxe ${rk.posts.length} posts para @${username}`);
        try {
          const vuR = await getCollection('validated_insta_users');
          await vuR.updateOne({ username }, { $set: { latestPosts: rk.posts, lastPostsAt: new Date().toISOString() } });
        } catch (_) {}
        if (debugInsert) return res.json({ success: true, username, posts: rk.posts, source: 'rocketapi', debugInsert: debugInfo });
        return res.json({ success: true, username, posts: rk.posts, source: 'rocketapi' });
      }
      console.log('[API] RocketAPI sem posts:', (rk && rk.error) || 'desconhecido', (rk && rk.isPrivate) ? '(privado)' : '');
    } catch (e) { console.log('[API] RocketAPI erro:', e && e.message); }

    // Fallback: Tentar Apify (via verifyInstagramProfile que agora retorna posts)
    try {
        console.log('[API] tentando fallback APIFY');
        // Simulando req/res para verifyInstagramProfile ou chamando lógica direta
        // Vamos usar verifyInstagramProfile mas precisamos adaptar pois ele espera req, res e retorna cache/json
        // Melhor chamar a lógica de Apify diretamente ou usar uma função extraída.
        // Como verifyInstagramProfile já faz cache e tudo, podemos chamá-lo passando mocks ou extrair.
        // Para simplificar e manter DRY, vamos chamar verifyInstagramProfile se não tiver em cache
        
        // Hack: verificar cache primeiro
        const cached = getCachedProfile(username);
        let apifyData = cached;
        
        if (!apifyData || !apifyData.latestPosts) {
             // Se não tem cache ou cache sem posts, força verificação (que usa apify)
             // Precisamos de um jeito de chamar a lógica do Apify sem depender de req/res do express
             // Vamos duplicar a chamada do Apify aqui ou refatorar verifyInstagramProfile?
             // Refatorar é arriscado agora. Vamos duplicar a chamada do Apify para garantir posts.
             
             const apifyToken = process.env.APIFY_TOKEN;
                if (apifyToken) {
                 const apifyUrl = `https://api.apify.com/v2/acts/apify~instagram-profile-scraper/run-sync-get-dataset-items?token=${apifyToken}`;
                 const payload = { usernames: [username], resultsLimit: 1 };
                 const respA = await axios.post(apifyUrl, payload, { headers: { 'Content-Type': 'application/json' }, timeout: 30000 });
                 const itemsA = respA.data;
                 if (Array.isArray(itemsA) && itemsA.length > 0 && itemsA[0] && !itemsA[0].error) {
                     const item = itemsA[0];
                     if (item.latestPosts && Array.isArray(item.latestPosts)) {
                         const posts = item.latestPosts.map(p => ({
                             shortcode: p.shortCode || p.shortcode,
                             takenAt: (function () {
                                 // Apify devolve timestamp como string ISO (ex: "2023-01-01T...Z").
                                 // Normaliza SEMPRE para unix em segundos (o front espera segundos).
                                 const t = (p.timestamp != null && p.timestamp !== '') ? p.timestamp : p.date;
                                 if (t == null || t === '') return null;
                                 if (typeof t === 'number' && Number.isFinite(t)) return t > 1e12 ? Math.floor(t / 1000) : Math.floor(t);
                                 const ms = new Date(t).getTime();
                                 return (Number.isFinite(ms) && ms > 0) ? Math.floor(ms / 1000) : null;
                             })(),
                             isVideo: p.type === 'Video' || p.isVideo,
                             displayUrl: p.displayUrl || p.displayURL || p.imageUrl || p.thumbnailSrc,
                             videoUrl: p.videoUrl || p.videoURL,
                             typename: p.type === 'Video' ? 'GraphVideo' : 'GraphImage'
                         })).slice(0, 12);
                         return res.json({ success: true, username, posts, debugInsert: debugInsert ? debugInfo : undefined });
                     }
                 }
             }
        } else if (apifyData && apifyData.latestPosts) {
             return res.json({ success: true, username, posts: apifyData.latestPosts, debugInsert: debugInsert ? debugInfo : undefined });
        }
    } catch (eApify) { console.error('[API] Fallback Apify error:', eApify.message); }

    try {
      console.log('[API] tentando fallback HTML');
      const basic = await fetchInstagramPosts(username);
      if (basic && basic.success && Array.isArray(basic.posts) && basic.posts.length) {
        const posts = basic.posts.slice(0, 12).map(sc => ({ shortcode: sc, takenAt: null, isVideo: false, displayUrl: null, videoUrl: null }));
        try {
          const vu2 = await getCollection('validated_insta_users');
          await vu2.updateOne(
            { username },
            { $set: { latestPosts: posts, lastPostsAt: new Date().toISOString() } }
          );
        } catch (_) {}
        return res.json({ success: true, username, posts, debugInsert: debugInsert ? debugInfo : undefined });
      }
    } catch (e2) { /* sem fallback */ }

    // Último recurso: se já temos posts salvos (mesmo "velhos"), devolve eles. O front
    // renderiza pelo shortcode (embed do Instagram) mesmo se a URL da imagem tiver expirado,
    // então a grade nunca fica vazia quando já buscamos posts deste perfil antes.
    try {
      const vuLast = await getCollection('validated_insta_users');
      const old = await vuLast.findOne({ username }, { projection: { latestPosts: 1 } });
      if (old && Array.isArray(old.latestPosts) && old.latestPosts.length) {
        return res.json({ success: true, username, posts: old.latestPosts, stale: true, debugInsert: debugInsert ? debugInfo : undefined });
      }
    } catch (_) {}

    return res.json({ success: true, username, posts: [], debugInsert: debugInsert ? debugInfo : undefined });
  } catch (e) {
    return res.status(500).json({ success: false, error: e?.message || String(e) });
  }
});

app.post('/api/instagram/select-post', async (req, res) => {
  try {
    const username = String((req.body && req.body.username) || '').trim();
    const shortcode = String((req.body && req.body.shortcode) || '').trim();
    if (!shortcode) {
      return res.status(400).json({ success: false, error: 'missing_shortcode' });
    }
    const link = `https://www.instagram.com/p/${encodeURIComponent(shortcode)}/`;
    const prev = Array.isArray(req.session.selectedPosts) ? req.session.selectedPosts : [];
    const filtered = prev.filter(p => p.shortcode !== shortcode);
    const selected = { username, shortcode, link, savedAt: new Date().toISOString() };
    req.session.selectedPosts = [selected, ...filtered].slice(0, 50);
    return res.json({ success: true, selectedPost: selected, selectedPosts: req.session.selectedPosts });
  } catch (e) {
    return res.status(500).json({ success: false, error: e?.message || String(e) });
  }
});

app.get('/api/instagram/selected-posts', async (req, res) => {
  try {
    const list = Array.isArray(req.session.selectedPosts) ? req.session.selectedPosts : [];
    return res.json({ success: true, posts: list });
  } catch (e) {
    return res.status(500).json({ success: false, error: e?.message || String(e) });
  }
});

app.post('/api/instagram/select-post-for', async (req, res) => {
  try {
    const username = String((req.body && req.body.username) || '').trim();
    const shortcode = String((req.body && req.body.shortcode) || '').trim();
    const kind = String((req.body && req.body.kind) || '').trim();
    const mode = String((req.body && req.body.mode) || '').trim().toLowerCase();
    if (!kind) { return res.status(400).json({ success: false, error: 'missing_kind' }); }
    if (!shortcode && mode !== 'remove') { return res.status(400).json({ success: false, error: 'missing_shortcode' }); }
    const link = `https://www.instagram.com/p/${encodeURIComponent(shortcode)}/`;
    if (!req.session.selectedFor) req.session.selectedFor = {};
    const prevObj = req.session.selectedFor[kind] || {};
    const prevList = Array.isArray(prevObj.shortcodes) ? prevObj.shortcodes : (prevObj.shortcode ? [prevObj.shortcode] : []);
    const replace = mode !== 'append';
    if (mode === 'remove') {
      const nextList = prevList.filter(x => x !== shortcode);
      if (!nextList.length) {
        if (req.session.selectedFor[kind]) delete req.session.selectedFor[kind];
      } else {
        req.session.selectedFor[kind] = {
          username: username || prevObj.username || '',
          shortcodes: nextList,
          shortcode: nextList[0] || '',
          link: nextList[0] ? `https://www.instagram.com/p/${encodeURIComponent(nextList[0])}/` : '',
          savedAt: new Date().toISOString()
        };
      }
      req.session.selectedPosts = Array.isArray(req.session.selectedPosts) ? req.session.selectedPosts : [];
      req.session.selectedPosts = req.session.selectedPosts.filter(p => p && p.shortcode !== shortcode);
      return res.json({ success: true, selectedFor: req.session.selectedFor });
    }
    const nextList = replace ? [shortcode] : (prevList.includes(shortcode) ? prevList : prevList.concat([shortcode]));
    req.session.selectedFor[kind] = {
      username: username || prevObj.username || '',
      shortcodes: nextList,
      shortcode: nextList[0] || shortcode,
      link,
      savedAt: new Date().toISOString()
    };
    req.session.selectedPosts = Array.isArray(req.session.selectedPosts) ? req.session.selectedPosts : [];
    nextList.forEach((code) => {
      if (!req.session.selectedPosts.find(p => p.shortcode === code)) {
        req.session.selectedPosts.push({ shortcode: code, username });
      }
    });
    return res.json({ success: true, selected: req.session.selectedFor[kind], selectedFor: req.session.selectedFor });
  } catch (e) {
    return res.status(500).json({ success: false, error: e?.message || String(e) });
  }
});

