app.get('/painel/recuperacao', requireAdmin, async (req, res) => {
  try {
    const { getCollection } = require('./mongodbClient');
    const col = await getCollection('checkout_orders');

    const cutoffDate = new Date(Date.now() - 15 * 60 * 1000).toISOString();
    const period = String(req.query.period || '').trim() || 'all';
    const startDate = String(req.query.startDate || '').trim();
    const endDate = String(req.query.endDate || '').trim();

    const now = new Date();
    const nowSP = new Date(now.getTime() - 3 * 60 * 60 * 1000);
    const startOfTodayUtc = new Date(Date.UTC(nowSP.getUTCFullYear(), nowSP.getUTCMonth(), nowSP.getUTCDate(), 3, 0, 0, 0));
    const startOfTomorrowUtc = (() => { const d = new Date(startOfTodayUtc); d.setUTCDate(d.getUTCDate() + 1); return d; })();

    const dateRange = { $lt: cutoffDate };
    const minIso = (a, b) => {
      const aa = String(a || '').trim();
      const bb = String(b || '').trim();
      if (!aa) return bb;
      if (!bb) return aa;
      return aa < bb ? aa : bb;
    };

    const buildMetricsRangeIso = () => {
      try {
        const nowIso = new Date().toISOString();
        const range = { ltIso: nowIso, gteIso: '' };
        if (period && period !== 'all') {
          if (period === 'today') {
            range.gteIso = startOfTodayUtc.toISOString();
            range.ltIso = startOfTomorrowUtc.toISOString();
          } else if (period === 'last3days') {
            const s = new Date(startOfTodayUtc);
            s.setUTCDate(s.getUTCDate() - 2);
            range.gteIso = s.toISOString();
            range.ltIso = startOfTomorrowUtc.toISOString();
          } else if (period === 'last7days') {
            const s = new Date(startOfTodayUtc);
            s.setUTCDate(s.getUTCDate() - 6);
            range.gteIso = s.toISOString();
            range.ltIso = startOfTomorrowUtc.toISOString();
          } else if (period === 'thismonth') {
            const sSp = new Date(nowSP.getTime());
            sSp.setUTCDate(1);
            const sUtc = new Date(Date.UTC(sSp.getUTCFullYear(), sSp.getUTCMonth(), sSp.getUTCDate(), 3, 0, 0, 0));
            range.gteIso = sUtc.toISOString();
            range.ltIso = startOfTomorrowUtc.toISOString();
          } else if (period === 'lastmonth') {
            const startSp = new Date(nowSP.getTime());
            startSp.setUTCDate(1);
            startSp.setUTCMonth(startSp.getUTCMonth() - 1);
            const endSp = new Date(nowSP.getTime());
            endSp.setUTCDate(1);
            const sUtc = new Date(Date.UTC(startSp.getUTCFullYear(), startSp.getUTCMonth(), startSp.getUTCDate(), 3, 0, 0, 0));
            const eUtc = new Date(Date.UTC(endSp.getUTCFullYear(), endSp.getUTCMonth(), endSp.getUTCDate(), 3, 0, 0, 0));
            range.gteIso = sUtc.toISOString();
            range.ltIso = eUtc.toISOString();
          } else if (period === 'custom') {
            if (startDate) {
              const start = new Date(`${startDate}T00:00:00.000Z`);
              start.setUTCHours(start.getUTCHours() + 3);
              range.gteIso = start.toISOString();
            }
            if (endDate) {
              const end = new Date(`${endDate}T23:59:59.999Z`);
              end.setUTCHours(end.getUTCHours() + 3);
              range.ltIso = end.toISOString();
            }
          }
        } else if (startDate || endDate) {
          if (startDate) {
            const start = new Date(`${startDate}T00:00:00.000Z`);
            start.setUTCHours(start.getUTCHours() + 3);
            range.gteIso = start.toISOString();
          }
          if (endDate) {
            const end = new Date(`${endDate}T23:59:59.999Z`);
            end.setUTCHours(end.getUTCHours() + 3);
            range.ltIso = end.toISOString();
          }
        }
        range.ltIso = String(range.ltIso || nowIso).trim() || nowIso;
        range.gteIso = String(range.gteIso || '').trim();
        return range;
      } catch (_) {
        return { gteIso: '', ltIso: new Date().toISOString() };
      }
    };

    if (period && period !== 'all') {
      if (period === 'today') {
        dateRange.$gte = startOfTodayUtc.toISOString();
      } else if (period === 'last3days') {
        const s = new Date(startOfTodayUtc);
        s.setUTCDate(s.getUTCDate() - 2);
        dateRange.$gte = s.toISOString();
      } else if (period === 'last7days') {
        const s = new Date(startOfTodayUtc);
        s.setUTCDate(s.getUTCDate() - 6);
        dateRange.$gte = s.toISOString();
      } else if (period === 'thismonth') {
        const sSp = new Date(nowSP.getTime());
        sSp.setUTCDate(1);
        const sUtc = new Date(Date.UTC(sSp.getUTCFullYear(), sSp.getUTCMonth(), sSp.getUTCDate(), 3, 0, 0, 0));
        dateRange.$gte = sUtc.toISOString();
      } else if (period === 'lastmonth') {
        const startSp = new Date(nowSP.getTime());
        startSp.setUTCDate(1);
        startSp.setUTCMonth(startSp.getUTCMonth() - 1);
        const endSp = new Date(nowSP.getTime());
        endSp.setUTCDate(1);

        const sUtc = new Date(Date.UTC(startSp.getUTCFullYear(), startSp.getUTCMonth(), startSp.getUTCDate(), 3, 0, 0, 0));
        const eUtc = new Date(Date.UTC(endSp.getUTCFullYear(), endSp.getUTCMonth(), endSp.getUTCDate(), 3, 0, 0, 0));
        dateRange.$gte = sUtc.toISOString();
        dateRange.$lt = minIso(dateRange.$lt, eUtc.toISOString());
      } else if (period === 'custom') {
        if (startDate) {
          const start = new Date(`${startDate}T00:00:00.000Z`);
          start.setUTCHours(start.getUTCHours() + 3);
          dateRange.$gte = start.toISOString();
        }
        if (endDate) {
          const end = new Date(`${endDate}T23:59:59.999Z`);
          end.setUTCHours(end.getUTCHours() + 3);
          dateRange.$lt = minIso(dateRange.$lt, end.toISOString());
        }
      }
    } else if (startDate || endDate) {
      if (startDate) {
        const start = new Date(`${startDate}T00:00:00.000Z`);
        start.setUTCHours(start.getUTCHours() + 3);
        dateRange.$gte = start.toISOString();
      }
      if (endDate) {
        const end = new Date(`${endDate}T23:59:59.999Z`);
        end.setUTCHours(end.getUTCHours() + 3);
        dateRange.$lt = minIso(dateRange.$lt, end.toISOString());
      }
    }

    const normalizeUsername = (u) => {
      try {
        let s = String(u || '').trim();
        if (!s) return '';
        s = s.replace(/\s+/g, '');
        s = s.replace(/^@/, '');
        s = s.split('#')[0].split('?')[0];
        if (s.includes('/')) {
          const parts = s.split('/').filter(Boolean);
          s = parts.length ? parts[parts.length - 1] : s;
        }
        return String(s || '').toLowerCase().trim();
      } catch (_) {
        return '';
      }
    };

    const extractUsername = (o) => {
      try {
        const paidArr = Array.isArray(o?.additionalInfoPaid) ? o.additionalInfoPaid : [];
        const baseArr = Array.isArray(o?.additionalInfo) ? o.additionalInfo : [];
        return o.instagramUsername
          || o.instauser
          || (o.additionalInfoMapPaid && o.additionalInfoMapPaid.instagram_username)
          || (o.additionalInfoMap && o.additionalInfoMap.instagram_username)
          || paidArr.find(i => i && i.key === 'instagram_username')?.value
          || baseArr.find(i => i && i.key === 'instagram_username')?.value
          || '';
      } catch (_) {
        return '';
      }
    };

    const query = {
      $and: [
        { status: { $ne: 'pago' } },
        { 'woovi.status': { $ne: 'pago' } },
        { createdAt: dateRange }
      ]
    };

    // Get pending orders (limit to recent 200 to avoid overload)
    let pendingOrders = await col.find(query).sort({ createdAt: -1 }).limit(200).toArray();

    if (pendingOrders.length > 0) {
      // Logic to filter out orders where the user paid in a subsequent order
      // Extract usernames and phones
      const usernames = pendingOrders
        .map(o => extractUsername(o))
        .filter(u => u && typeof u === 'string')
        .map(u => normalizeUsername(u));

      const phones = pendingOrders
        .map(o => (o.customer && (o.customer.phone || o.customer.phone_number)))
        .filter(p => p && typeof p === 'string');
      
      const uniqueUsernames = [...new Set(usernames)].filter(Boolean);
      
      // Escape special characters for Regex
      const escapeRegExp = (string) => {
        return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      };

      if (uniqueUsernames.length > 0) {
         // Find any PAID orders for these users created after the oldest pending order in this batch
         const oldestPending = pendingOrders[pendingOrders.length - 1].createdAt;
         
         const usernameRegexes = uniqueUsernames.map(u => new RegExp(escapeRegExp(u), 'i'));

         const paidQuery = {
            $and: [
              {
                $or: [
                  { status: 'pago' },
                  { 'woovi.status': 'pago' }
                ]
              },
              {
                $or: [
                   { instagramUsername: { $in: usernameRegexes } },
                   { instauser: { $in: usernameRegexes } },
                   { 'additionalInfoMap.instagram_username': { $in: usernameRegexes } },
                   { 'additionalInfoMapPaid.instagram_username': { $in: usernameRegexes } }
                ]
              },
              { createdAt: { $gt: oldestPending } }
            ]
         };

         const paidOrders = await col.find(paidQuery).project({ instagramUsername: 1, instauser: 1, additionalInfoMap: 1, additionalInfoMapPaid: 1, additionalInfoPaid: 1, additionalInfo: 1, createdAt: 1 }).toArray();
         const paidLatestByUser = new Map();
         for (const paid of paidOrders) {
           const u = normalizeUsername(extractUsername(paid));
           if (!u) continue;
           const ms = new Date(paid.createdAt).getTime();
           if (!Number.isFinite(ms)) continue;
           const prev = paidLatestByUser.get(u) || 0;
           if (ms > prev) paidLatestByUser.set(u, ms);
         }
         
         // Filter pending orders
         pendingOrders = pendingOrders.filter(pending => {
            // Normalize pending user
            let pUser = normalizeUsername(extractUsername(pending));
            if (!pUser) return true; // Keep if no username to match

            const pendingMs = new Date(pending.createdAt).getTime();
            const paidLatestMs = paidLatestByUser.get(pUser) || 0;
            const hasNewerPaid = Number.isFinite(pendingMs) && paidLatestMs > pendingMs;

            return !hasNewerPaid;
         });
      }
    }

    const seen = new Set();
    pendingOrders = pendingOrders.filter(o => {
      const key = normalizeUsername(extractUsername(o));
      if (!key) return true;
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });

    const sumCents = pendingOrders.reduce((acc, o) => {
      const v = Number(o?.valueCents || o?.total_cents || 0);
      return acc + (Number.isFinite(v) ? v : 0);
    }, 0);

    const metricsRange = buildMetricsRangeIso();
    const stageCountFilter = (field) => {
      const q = {};
      q[field] = { $exists: true, $nin: [null, ''] };
      if (metricsRange.gteIso) q[field].$gte = metricsRange.gteIso;
      if (metricsRange.ltIso) q[field].$lt = metricsRange.ltIso;
      return q;
    };
    const recoveredFilter = (field) => {
      const q = {};
      q[field] = { $exists: true, $nin: [null, ''] };
      if (metricsRange.gteIso) q[field].$gte = metricsRange.gteIso;
      if (metricsRange.ltIso) q[field].$lt = metricsRange.ltIso;
      return q;
    };

    const [email1Count, email2Count, email3Count] = await Promise.all([
      col.countDocuments(stageCountFilter('emails.paymentRecoveryStage10SentAt')).catch(() => 0),
      col.countDocuments(stageCountFilter('emails.paymentRecoveryStage15SentAt')).catch(() => 0),
      col.countDocuments(stageCountFilter('emails.paymentRecoveryStage30SentAt')).catch(() => 0)
    ]);

    const recoveredAgg = await col.aggregate([
      {
        $match: {
          $and: [
            {
              $or: [
                { status: 'pago' },
                { 'woovi.status': 'pago' },
                { paidAt: { $exists: true, $nin: [null, ''] } },
                { 'woovi.paidAt': { $exists: true, $nin: [null, ''] } },
                { 'paghiper.paidAt': { $exists: true, $nin: [null, ''] } },
                { 'payment.paidAt': { $exists: true, $nin: [null, ''] } },
                { 'expay.paidAt': { $exists: true, $nin: [null, ''] } },
                { 'efi.paidAt': { $exists: true, $nin: [null, ''] } }
              ]
            },
            {
              $or: [
                { 'emails.paymentRecoveryStage10SentAt': { $exists: true, $nin: [null, ''] } },
                { 'emails.paymentRecoveryStage15SentAt': { $exists: true, $nin: [null, ''] } },
                { 'emails.paymentRecoveryStage30SentAt': { $exists: true, $nin: [null, ''] } }
              ]
            }
          ]
        }
      },
      {
        $addFields: {
          __paidAtEff: {
            $ifNull: [
              '$paidAt',
              {
                $ifNull: [
                  '$woovi.paidAt',
                  {
                    $ifNull: [
                      '$paghiper.paidAt',
                      {
                        $ifNull: [
                          '$payment.paidAt',
                          {
                            $ifNull: ['$expay.paidAt', '$efi.paidAt']
                          }
                        ]
                      }
                    ]
                  }
                ]
              }
            ]
          },
          __lastRecoveryEmailAt: {
            $max: [
              '$emails.paymentRecoveryStage10SentAt',
              '$emails.paymentRecoveryStage15SentAt',
              '$emails.paymentRecoveryStage30SentAt'
            ]
          }
        }
      },
      {
        $match: {
          $expr: {
            $gt: ['$__paidAtEff', '$__lastRecoveryEmailAt']
          }
        }
      },
      ...(metricsRange.gteIso || metricsRange.ltIso ? [{
        $match: {
          __paidAtEff: Object.assign(
            {},
            (metricsRange.gteIso ? { $gte: metricsRange.gteIso } : {}),
            (metricsRange.ltIso ? { $lt: metricsRange.ltIso } : {})
          )
        }
      }] : []),
      {
        $addFields: {
          __stage: {
            $switch: {
              branches: [
                { case: { $eq: ['$__lastRecoveryEmailAt', '$emails.paymentRecoveryStage30SentAt'] }, then: 3 },
                { case: { $eq: ['$__lastRecoveryEmailAt', '$emails.paymentRecoveryStage15SentAt'] }, then: 2 },
                { case: { $eq: ['$__lastRecoveryEmailAt', '$emails.paymentRecoveryStage10SentAt'] }, then: 1 }
              ],
              default: 0
            }
          }
        }
      },
      { $match: { __stage: { $in: [1, 2, 3] } } },
      {
        $group: {
          _id: '$__stage',
          orders: { $sum: 1 },
          valueCents: { $sum: { $ifNull: ['$valueCents', 0] } }
        }
      }
    ]).toArray().catch(() => []);
    const recoveredByStage = (Array.isArray(recoveredAgg) ? recoveredAgg : []).reduce((acc, row) => {
      const k = String(row?._id || '').trim();
      acc[k] = { orders: Number(row?.orders || 0) || 0, valueCents: Number(row?.valueCents || 0) || 0 };
      return acc;
    }, {});
    const recoveredTotal = Object.values(recoveredByStage).reduce((acc, it) => {
      return { orders: acc.orders + (Number(it.orders || 0) || 0), valueCents: acc.valueCents + (Number(it.valueCents || 0) || 0) };
    }, { orders: 0, valueCents: 0 });

    res.render('painel_recuperacao', {
      orders: pendingOrders,
      period,
      startDate,
      endDate,
      sumCents,
      metrics: {
        range: metricsRange,
        sent: { email1: email1Count, email2: email2Count, email3: email3Count },
        recovered: { total: recoveredTotal, byStage: recoveredByStage }
      }
    });
  } catch (err) {
    console.error('Error in /painel/recuperacao:', err);
    res.status(500).send('Internal Server Error');
  }
});

