app.get('/api/painel/whatsapp-sales', requireAdmin, async (req, res) => {
  try {
    const { getCollection } = require('./mongodbClient');
    const col = await getCollection('checkout_orders');
    const limitRaw = Number(req.query?.limit || 50) || 50;
    const limit = Math.min(200, Math.max(1, Math.floor(limitRaw)));
    const purchaseRaw = String(req.query?.purchase || '').trim();

    const wppBaseQuery = { $or: [{ saleChannel: 'whatsapp' }, { isWhatsappSale: true }, { 'additionalInfoMapPaid.saleChannel': 'whatsapp' }, { 'additionalInfoMap.saleChannel': 'whatsapp' }] };
    let query = wppBaseQuery;

    if (purchaseRaw) {
      const safe = purchaseRaw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const rx = new RegExp(safe, 'i');
      const digits = purchaseRaw.replace(/\D/g, '');
      const usernameRaw = purchaseRaw.replace(/^@+/, '').trim();
      const orConds = [
        { identifier: rx },
        { correlationID: rx },
        { instagramUsername: rx },
        { instauser: rx },
        { 'additionalInfoMapPaid.instagram_username': rx },
        { 'additionalInfoMapPaid.phone': rx },
        { 'additionalInfoPaid': { $elemMatch: { key: 'instagram_username', value: rx } } },
        { 'additionalInfoPaid': { $elemMatch: { key: 'phone', value: rx } } }
      ];

      if (digits && digits.length >= 6) {
        const digitsRx = new RegExp(digits.split('').join('\\D*'), 'i');
        orConds.push({ 'customer.phone': { $regex: digitsRx } });
      }

      if (/^[0-9a-fA-F]{24}$/.test(purchaseRaw)) {
        try {
          const { ObjectId } = require('mongodb');
          orConds.push({ _id: new ObjectId(purchaseRaw) });
        } catch (_) {}
      }

      if (usernameRaw) {
        const userSafe = usernameRaw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const userRx = new RegExp(userSafe, 'i');
        orConds.push({ instagramUsername: userRx });
        orConds.push({ instauser: userRx });
        orConds.push({ 'additionalInfoMapPaid.instagram_username': userRx });
      }

      query = { $and: [wppBaseQuery, { $or: orConds }] };
    }

    const docs = await col.find(
      query,
      { projection: { _id: 1, createdAt: 1, paidAt: 1, woovi: 1, status: 1, customer: 1, instagramUsername: 1, instauser: 1, tipo: 1, tipoServico: 1, qtd: 1, quantidade: 1, additionalInfoMapPaid: 1, additionalInfoPaid: 1 } }
    ).sort({ createdAt: -1, _id: -1 }).limit(limit).toArray();
    res.json({ ok: true, sales: docs });
  } catch (e) {
    res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.post('/api/painel/whatsapp-sales', requireAdmin, async (req, res) => {
  try {
    const body = req.body || {};
    const phoneRaw = String(body.phone || '').trim();
    const phoneDigits = phoneRaw.replace(/\D/g, '');
    const phone = phoneDigits ? (`+55${phoneDigits.replace(/^55/, '')}`) : '';
    const usernameRaw = String(body.username || body.instauser || body.instagram_username || '').trim();
    const username = usernameRaw.replace(/^@+/, '').trim();
    const tipoRaw = String(body.tipo || body.tipoServico || body.serviceType || '').trim();
    const tipo = tipoRaw ? tipoRaw : '';
    const qty = Math.max(0, Math.floor(Number(body.quantidade || body.qtd || 0) || 0));
    const parseMoneyToCents = (v) => {
      const raw = String(v == null ? '' : v).trim();
      if (!raw) return 0;
      let s = raw.replace(/[^\d,.\-]/g, '');
      const hasComma = s.includes(',');
      const hasDot = s.includes('.');
      if (hasComma && hasDot) {
        if (s.lastIndexOf(',') > s.lastIndexOf('.')) {
          s = s.replace(/\./g, '').replace(/,/g, '.');
        } else {
          s = s.replace(/,/g, '');
        }
      } else if (hasComma && !hasDot) {
        s = s.replace(/,/g, '.');
      }
      const n = Number(s);
      if (!Number.isFinite(n) || n <= 0) return 0;
      return Math.round(n * 100);
    };
    const valueCents = parseMoneyToCents(body.value || body.valor || 0);

    if (!phone || phone.replace(/\D/g, '').length < 10) return res.status(400).json({ ok: false, error: 'Telefone inválido' });
    if (!username) return res.status(400).json({ ok: false, error: 'Perfil inválido' });
    if (!tipo) return res.status(400).json({ ok: false, error: 'Tipo inválido' });
    if (!qty) return res.status(400).json({ ok: false, error: 'Quantidade inválida' });

    const now = new Date();
    const nowIso = now.toISOString();
    const rand = Math.random().toString(36).slice(2, 8);
    const identifier = `wpp_${Date.now()}_${rand}`;
    const correlationID = `wpp_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

    const additionalInfoMapPaid = {
      phone: phoneDigits.replace(/^55/, ''),
      instagram_username: username,
      categoria_servico: 'seguidores',
      tipo_servico: tipo,
      quantidade: String(qty),
      saleChannel: 'whatsapp'
    };
    if (valueCents) additionalInfoMapPaid.valor = String((valueCents / 100).toFixed(2));

    const additionalInfoPaid = Object.keys(additionalInfoMapPaid).map((k) => ({ key: k, value: String(additionalInfoMapPaid[k]) }));

    const doc = {
      createdAt: now,
      paidAt: nowIso,
      status: 'pago',
      woovi: { status: 'pago', paidAt: nowIso, paymentMethods: { pix: { value: valueCents || 0 } } },
      valueCents: valueCents || 0,
      identifier,
      correlationID,
      customer: { phone },
      instagramUsername: username,
      instauser: username,
      tipo,
      tipoServico: tipo,
      qtd: qty,
      quantidade: qty,
      additionalInfoPaid,
      additionalInfoMapPaid,
      saleChannel: 'whatsapp',
      isWhatsappSale: true
    };

    const { getCollection } = require('./mongodbClient');
    const col = await getCollection('checkout_orders');
    const ins = await col.insertOne(doc);
    res.json({ ok: true, id: ins?.insertedId ? String(ins.insertedId) : null });
  } catch (e) {
    res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.get('/api/painel/whatsapp-sales/followers-current', requireAdmin, async (req, res) => {
  try {
    const purchaseRaw = String(req.query?.purchase || '').trim();
    const force = String(req.query?.force || '').trim() === '1';
    if (!purchaseRaw) return res.status(400).json({ ok: false, error: 'missing_purchase' });

    const { getCollection } = require('./mongodbClient');
    const col = await getCollection('checkout_orders');

    const wppBaseQuery = { $or: [{ saleChannel: 'whatsapp' }, { isWhatsappSale: true }, { 'additionalInfoMapPaid.saleChannel': 'whatsapp' }, { 'additionalInfoMap.saleChannel': 'whatsapp' }] };

    const safe = purchaseRaw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const rx = new RegExp(safe, 'i');
    const digits = purchaseRaw.replace(/\D/g, '');
    const usernameCandidate = purchaseRaw.replace(/^@+/, '').trim();
    const orConds = [
      { identifier: rx },
      { correlationID: rx },
      { instagramUsername: rx },
      { instauser: rx },
      { 'additionalInfoMapPaid.instagram_username': rx },
      { 'additionalInfoMapPaid.phone': rx },
      { 'additionalInfoPaid': { $elemMatch: { key: 'instagram_username', value: rx } } },
      { 'additionalInfoPaid': { $elemMatch: { key: 'phone', value: rx } } }
    ];

    if (digits && digits.length >= 6) {
      const digitsRx = new RegExp(digits.split('').join('\\D*'), 'i');
      orConds.push({ 'customer.phone': { $regex: digitsRx } });
    }

    if (/^[0-9a-fA-F]{24}$/.test(purchaseRaw)) {
      try {
        const { ObjectId } = require('mongodb');
        orConds.push({ _id: new ObjectId(purchaseRaw) });
      } catch (_) {}
    }

    if (usernameCandidate) {
      const userSafe = usernameCandidate.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      const userRx = new RegExp(userSafe, 'i');
      orConds.push({ instagramUsername: userRx });
      orConds.push({ instauser: userRx });
      orConds.push({ 'additionalInfoMapPaid.instagram_username': userRx });
    }

    const doc = await col.findOne(
      { $and: [wppBaseQuery, { $or: orConds }] },
      { projection: { _id: 1, createdAt: 1, paidAt: 1, woovi: 1, identifier: 1, correlationID: 1, status: 1, customer: 1, instagramUsername: 1, instauser: 1, tipo: 1, tipoServico: 1, qtd: 1, quantidade: 1, additionalInfoMapPaid: 1, additionalInfoPaid: 1 } }
    );
    if (!doc) return res.status(404).json({ ok: false, error: 'not_found' });

    const pickInfoPaid = (o, key) => {
      try {
        if (o && o.additionalInfoMapPaid && typeof o.additionalInfoMapPaid[key] !== 'undefined') return o.additionalInfoMapPaid[key];
        const arrPaid = Array.isArray(o && o.additionalInfoPaid) ? o.additionalInfoPaid : [];
        const itemPaid = arrPaid.find(i => i && i.key === key);
        if (itemPaid && typeof itemPaid.value !== 'undefined') return itemPaid.value;
      } catch (_) {}
      return '';
    };

    const usernameRaw = String(pickInfoPaid(doc, 'instagram_username') || doc.instagramUsername || doc.instauser || '').trim();
    const username = usernameRaw.toLowerCase().replace(/^@+/, '').trim();
    if (!username) return res.status(400).json({ ok: false, error: 'missing_username' });

    const out = await followersMgmtGetCurrent(req, username, force);
    return res.status(out.code).json({
      purchase: purchaseRaw,
      sale: {
        id: doc._id ? String(doc._id) : null,
        identifier: doc.identifier ? String(doc.identifier) : null,
        correlationID: doc.correlationID ? String(doc.correlationID) : null,
        phone: (doc.customer && doc.customer.phone) ? String(doc.customer.phone) : null,
        paidAt: doc.woovi?.paidAt || doc.paidAt || doc.createdAt || null,
        tipo: String(pickInfoPaid(doc, 'tipo_servico') || doc.tipoServico || doc.tipo || '').trim() || null,
        quantidade: Number(doc.quantidade || doc.qtd || pickInfoPaid(doc, 'quantidade') || 0) || null
      },
      ...out.body
    });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

const followersMgmtSerial = new Map();
const followersMgmtThrottle = new Map();
const followersMgmtEnqueue = (key, fn) => {
  const prev = followersMgmtSerial.get(key) || Promise.resolve();
  const next = prev.catch(() => undefined).then(fn);
  followersMgmtSerial.set(key, next.finally(() => {
    try {
      if (followersMgmtSerial.get(key) === next) followersMgmtSerial.delete(key);
    } catch (_) {}
  }));
  return next;
};

const fetchInstagramFollowersInfoRocketApi = async (username) => {
  try {
    if (!process.env.ROCKETAPI_TOKEN) return { success: false, error: 'rocketapi_token_missing' };
    if (global.rocketApiDisabledUntil && Date.now() <= global.rocketApiDisabledUntil) return { success: false, error: 'rocketapi_temporarily_disabled' };

    const rocketUrl = 'https://v1.rocketapi.io/instagram/user/get_info';
    const rocketResp = await axios.post(
      rocketUrl,
      { username },
      { headers: { Authorization: `Token ${process.env.ROCKETAPI_TOKEN}` }, timeout: 15000, validateStatus: () => true }
    );

    if (rocketResp.status !== 200) return { success: false, error: `rocket_http_${rocketResp.status}` };

    const rData = rocketResp.data;
    const isRocketOk = rData && (rData.status === 'ok' || rData.status === 'done');
    const rUser = isRocketOk ? (rData?.response?.body?.data?.user || null) : null;
    if (!rUser || !rUser.username) {
      const msg = String(JSON.stringify(rData || {}).slice(0, 400)).toLowerCase();
      if (msg.includes('expired') || msg.includes('renew') || msg.includes('plan is')) global.rocketApiDisabledUntil = Date.now() + (10 * 60 * 1000);
      return { success: false, error: 'rocket_invalid_data' };
    }

    global.rocketApiDisabledUntil = 0;

    const followersCount = (rUser.edge_followed_by && typeof rUser.edge_followed_by.count === 'number') ? rUser.edge_followed_by.count : null;
    const profilePicUrl = (function(){
      try {
        const u = String(rUser.profile_pic_url_hd || rUser.profile_pic_url || '').trim();
        return u || null;
      } catch (_) {
        return null;
      }
    })();
    return {
      success: true,
      profile: {
        username: String(rUser.username || username),
        followersCount,
        profilePicUrl,
        isPrivate: !!rUser.is_private,
        checkedAt: new Date().toISOString(),
        source: 'rocket_api'
      }
    };
  } catch (e) {
    const msg = String(e?.response?.data || e?.message || e || '').toLowerCase();
    if (msg.includes('expired')) global.rocketApiDisabledUntil = Date.now() + (10 * 60 * 1000);
    return { success: false, error: e?.message || String(e) };
  }
};

const fetchInstagramFollowersInfoInstagramProxy = async (username) => {
  const safeJsonResponse = (data) => {
    try {
      if (data == null) return null;
      if (typeof data === 'string') return JSON.parse(data);
      if (typeof data === 'object') return data;
      return null;
    } catch (_) {
      return null;
    }
  };
  const safeInt = (v) => {
    try {
      if (typeof v === 'number' && Number.isFinite(v)) return Math.trunc(v);
      const s0 = String(v == null ? '' : v).trim();
      if (!s0) return null;
      const s = s0.replace(/\s+/g, '');
      const normalizeThousands = (raw) => {
        const x0 = String(raw || '').trim();
        if (!x0) return '';
        const x = x0.replace(/\s+/g, '');
        if (/^\d{1,3}(\.\d{3})+(,\d+)?$/.test(x)) return x.replace(/\./g, '').replace(',', '.');
        if (/^\d{1,3}(,\d{3})+(\.\d+)?$/.test(x)) return x.replace(/,/g, '');
        if (/^\d+(\.\d{3})+$/.test(x)) return x.replace(/\./g, '');
        if (/^\d+(,\d{3})+$/.test(x)) return x.replace(/,/g, '');
        return x0;
      };
      const n = Number(normalizeThousands(s));
      if (Number.isFinite(n)) return Math.trunc(n);
      const digits = s0.replace(/[^\d-]/g, '');
      if (!digits) return null;
      const n2 = Number(digits);
      return Number.isFinite(n2) ? Math.trunc(n2) : null;
    } catch (_) {
      return null;
    }
  };

  const timeoutMsRaw = Number(String(process.env.FOLLOWERS_MGMT_INSTAGRAM_PROXY_TIMEOUT_MS || process.env.REFIL2_UPSTREAM_TIMEOUT_MS || '12000').trim());
  const timeoutMs = (Number.isFinite(timeoutMsRaw) && timeoutMsRaw > 0) ? Math.max(5000, Math.min(60000, Math.trunc(timeoutMsRaw))) : 12000;

  const maxAttemptsRaw = Number(String(process.env.FOLLOWERS_MGMT_INSTAGRAM_PROXY_MAX_ATTEMPTS || process.env.REFIL2_UPSTREAM_MAX_ATTEMPTS || '2').trim());
  const maxAttempts = (Number.isFinite(maxAttemptsRaw) && maxAttemptsRaw > 0) ? Math.max(1, Math.min(4, Math.trunc(maxAttemptsRaw))) : 2;

  const waitMs = (ms) => new Promise((r) => setTimeout(r, ms));
  const requestWithRetry = async (fn) => {
    let lastErr = null;
    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        const resp = await fn();
        return resp;
      } catch (err) {
        lastErr = err;
        const code = String(err?.code || '').trim();
        const msg = String(err?.message || String(err) || '').trim();
        const retryable = code === 'ECONNABORTED' || code === 'ETIMEDOUT' || code === 'ECONNRESET' || /timeout/i.test(msg);
        if (!retryable || attempt === maxAttempts) throw err;
        await waitMs(250 * attempt);
      }
    }
    throw lastErr || new Error('upstream_failed');
  };

  try {
    const profileUrlCandidates = [
      `https://www.instagram.com/${username}/`,
      `https://instagram.com/${username}`,
      `https://www.instagram.com/${username}`
    ];
    const profileParamCandidates = ['name_url', 'url', 'link'];

    let lastStatus = null;
    let lastData = null;
    for (const paramName of profileParamCandidates) {
      for (const profileUrl of profileUrlCandidates) {
        const url = `https://www.refilfama24h.com/instagram_proxy.php?${paramName}=${encodeURIComponent(profileUrl)}`;
        const resp = await requestWithRetry(() => axios.get(url, { timeout: timeoutMs, validateStatus: () => true }));
        lastStatus = resp && typeof resp.status === 'number' ? resp.status : null;
        const json = safeJsonResponse(resp && resp.data);
        lastData = json;
        const first = Array.isArray(json) ? json[0] : json;

        const followersCount = safeInt(
          (first && (first.followerCount ?? first.follower_count ?? first.followers)) ??
          (first && first.data && (first.data.followerCount ?? first.data.follower_count ?? first.data.followers))
        );
        if (followersCount == null || !(followersCount > 0)) continue;

        const isPrivateRaw =
          (first && (first.isPrivate ?? first.is_private ?? first.private)) ??
          (first && first.data && (first.data.isPrivate ?? first.data.is_private ?? first.data.private));
        const isPrivate = (typeof isPrivateRaw === 'boolean')
          ? isPrivateRaw
          : (String(isPrivateRaw || '').trim().toLowerCase() === 'true' ? true : (String(isPrivateRaw || '').trim().toLowerCase() === 'false' ? false : null));

        return {
          success: true,
          profile: {
            username,
            followersCount,
            isPrivate,
            checkedAt: new Date().toISOString(),
            source: 'instagram_proxy'
          }
        };
      }
    }

    return { success: false, error: `instagram_proxy_failed${lastStatus ? `_http_${lastStatus}` : ''}`, detail: lastData ? 'has_data' : null };
  } catch (e) {
    return { success: false, error: e?.message || String(e) };
  }
};

// Consulta a API de profile dedicada (187.124.91.24) — retorna seguidores E status de privado.
// Usada no audit do gerenciamento de seguidores para detectar contas privadas.
const fetchInstagramProfileApiInfo = async (username) => {
  try {
    const base = String(process.env.PROFILE_API_URL || 'http://187.124.91.24:8080').replace(/\/+$/, '');
    const url = `${base}/api/profile?user=${encodeURIComponent(username)}`;
    const toMsRaw = Number(String(process.env.FOLLOWERS_MGMT_PROFILE_API_TIMEOUT_MS || process.env.REFIL2_UPSTREAM_TIMEOUT_MS || '12000').trim());
    const timeoutMs = (Number.isFinite(toMsRaw) && toMsRaw > 0) ? Math.max(5000, Math.min(60000, Math.trunc(toMsRaw))) : 12000;
    const resp = await axios.get(url, { timeout: timeoutMs, validateStatus: () => true });
    let root = resp ? resp.data : null;
    try { if (typeof root === 'string') { const s = root.trim(); root = (s.startsWith('{') || s.startsWith('[')) ? JSON.parse(s) : null; } } catch (_) { root = null; }
    if (Array.isArray(root)) root = root[0];
    if (!root || typeof root !== 'object') return { success: false, error: `profile_api_failed${resp && resp.status ? `_http_${resp.status}` : ''}` };
    const toInt = (v) => { if (typeof v === 'number' && Number.isFinite(v)) return Math.trunc(v); const d = String(v == null ? '' : v).replace(/[^\d-]/g, ''); if (!d) return null; const n = Number(d); return Number.isFinite(n) ? Math.trunc(n) : null; };
    const pickFollowers = (o, depth) => {
      if (!o || typeof o !== 'object' || depth > 4) return null;
      const direct = [o.followers, o.followerCount, o.follower_count, o.followers_count, o.followed_by, o.followers_total, o.total_followers, (o.edge_followed_by && o.edge_followed_by.count)];
      for (const c of direct) { const n = toInt(c); if (n != null && n > 0) return n; }
      for (const sub of ['data', 'user', 'profile', 'result', 'account', 'graphql']) { if (o[sub] && typeof o[sub] === 'object') { const n = pickFollowers(o[sub], depth + 1); if (n != null) return n; } }
      return null;
    };
    const pickPrivate = (o, depth) => {
      if (!o || typeof o !== 'object' || depth > 4) return null;
      const cands = [o.is_private, o.isPrivate, o.private, o.is_private_account, o.privateAccount, o.is_private_profile];
      for (const c of cands) {
        if (typeof c === 'boolean') return c;
        const s = String(c == null ? '' : c).trim().toLowerCase();
        if (s === 'true' || s === '1' || s === 'yes' || s === 'sim') return true;
        if (s === 'false' || s === '0' || s === 'no' || s === 'nao' || s === 'não') return false;
      }
      for (const sub of ['data', 'user', 'profile', 'result', 'account', 'graphql']) { if (o[sub] && typeof o[sub] === 'object') { const n = pickPrivate(o[sub], depth + 1); if (n != null) return n; } }
      return null;
    };
    const followersCount = pickFollowers(root, 0);
    const isPrivate = pickPrivate(root, 0);
    if ((followersCount == null || !(followersCount > 0)) && typeof isPrivate !== 'boolean') {
      return { success: false, error: `profile_api_no_data${resp && resp.status ? `_http_${resp.status}` : ''}` };
    }
    return { success: true, profile: { username, followersCount: (followersCount != null && followersCount > 0) ? followersCount : null, isPrivate: (typeof isPrivate === 'boolean') ? isPrivate : null, checkedAt: new Date().toISOString(), source: 'profile_api' } };
  } catch (e) {
    return { success: false, error: e?.message || String(e) };
  }
};

const followersMgmtGetCurrent = async (req, username, force) => {
  const { getCollection } = require('./mongodbClient');
  const monitorCol = await getCollection('followers_monitor');

  const key = String((req.session && req.session.adminUser && req.session.adminUser.username) ? req.session.adminUser.username : 'admin') + '|' + String(req.realIP || req.ip || '');

  return followersMgmtEnqueue(key, async () => {
    const traceId = Math.random().toString(36).slice(2, 8);
    const startedAtMs = Date.now();
    const cached = await monitorCol.findOne({ username }, { projection: { _id: 0 } });
    if (!force && cached && cached.checkedAt) {
      const cachedUsable = !!(
        (typeof cached.followersCount === 'number' && Number.isFinite(cached.followersCount) && cached.followersCount > 0) ||
        (typeof cached.isPrivate === 'boolean')
      );
      const diffDaysBrt = (function(){
        try {
          const brtOffsetMs = 3 * 60 * 60 * 1000;
          const toDayNum = (ms) => {
            const d = new Date(Number(ms || 0) - brtOffsetMs);
            if (!Number.isFinite(d.getTime())) return null;
            return Math.floor(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()) / (24 * 60 * 60 * 1000));
          };
          const nowNum = toDayNum(Date.now());
          const checkedNum = toDayNum(new Date(String(cached.checkedAt)).getTime());
          if (nowNum == null || checkedNum == null) return null;
          return nowNum - checkedNum;
        } catch (_) {
          return null;
        }
      })();
      if (diffDaysBrt != null && Number.isFinite(diffDaysBrt) && diffDaysBrt >= 0 && diffDaysBrt < 2) {
        if (cachedUsable) {
          try { console.log(`🧾 [followers-mgmt:${traceId}] cache-hit @${username} source=${String(cached.source || '')} ms=${Date.now() - startedAtMs}`); } catch (_) {}
          return { code: 200, body: { ok: true, cached: true, username, followersCount: cached.followersCount, isPrivate: cached.isPrivate, checkedAt: cached.checkedAt, source: cached.source || null } };
        }
        try { console.log(`🧾 [followers-mgmt:${traceId}] cache-bypass-invalid @${username} source=${String(cached.source || '')} fc=${(typeof cached.followersCount === 'number') ? cached.followersCount : ''} private=${typeof cached.isPrivate === 'boolean' ? (cached.isPrivate ? '1' : '0') : ''} ms=${Date.now() - startedAtMs}`); } catch (_) {}
      }
    }

    if (force && cached && cached.lastAttemptAt) {
      const ageMs = Date.now() - new Date(String(cached.lastAttemptAt)).getTime();
      if (Number.isFinite(ageMs) && ageMs >= 0 && ageMs < (60 * 1000)) {
        return {
          code: 200,
          body: {
            ok: true,
            cached: !!(cached && cached.checkedAt),
            stale: !!(cached && cached.checkedAt && (!cached.followersCount && cached.followersCount !== 0)),
            throttled: true,
            username,
            followersCount: cached.followersCount,
            isPrivate: cached.isPrivate,
            checkedAt: cached.checkedAt || null,
            source: cached.source || null,
            error: cached.error || null
          }
        };
      }
    }

    const sleep = (ms) => new Promise(r => setTimeout(r, ms));
    const minIntervalMs = 4500;
    const now = Date.now();
    const nextAllowedAt = Number(followersMgmtThrottle.get(key) || 0) || 0;
    const waitMs = Math.max(0, nextAllowedAt - now);
    if (waitMs > 0) await sleep(waitMs);
    await sleep(450 + Math.floor(Math.random() * 900));
    followersMgmtThrottle.set(key, Date.now() + minIntervalMs);

    let result = null;
    let profile = null;
    let source = 'instagram_proxy';
    let isPrivate = null;
    let followersCount = null;
    let error = null;
    let primaryReturnedZeroFollowers = false;

    for (let attempt = 1; attempt <= 1; attempt++) {
      try {
        try { console.log(`👣 [followers-mgmt:${traceId}] @${username} attempt=${attempt} method=instagram_proxy`); } catch (_) {}
        result = await fetchInstagramFollowersInfoInstagramProxy(username);
        profile = result && result.success ? result.profile : null;
        source = profile ? String(profile.source || 'instagram_proxy') : 'instagram_proxy';
        isPrivate = profile ? ((typeof profile.isPrivate === 'boolean') ? profile.isPrivate : null) : null;
        followersCount = profile && typeof profile.followersCount === 'number' ? profile.followersCount : null;
        error = result && !result.success ? (result.error || 'unknown_error') : null;
        if (typeof followersCount === 'number' && !(followersCount > 0)) {
          primaryReturnedZeroFollowers = true;
          followersCount = null;
          if (!error) error = 'invalid_followers_count';
        }
        if (profile) {
          try { console.log(`✅ [followers-mgmt:${traceId}] @${username} ok source=${source} private=${isPrivate === true ? '1' : (isPrivate === false ? '0' : '')} fc=${typeof followersCount === 'number' ? followersCount : ''} ms=${Date.now() - startedAtMs}`); } catch (_) {}
          break;
        }
      } catch (e) {
        error = e?.message || String(e);
        try { console.warn(`⚠️ [followers-mgmt:${traceId}] @${username} fail method=instagram_proxy attempt=${attempt}:`, error); } catch (_) {}
      }
      if (attempt < 1) await sleep(900 * attempt);
    }

    const nowIso = new Date().toISOString();
    let hasFresh = !!(profile && ((typeof followersCount === 'number' && followersCount > 0) || typeof isPrivate === 'boolean'));

    if (!hasFresh || primaryReturnedZeroFollowers) {
      try {
        try { console.log(`🚀 [followers-mgmt:${traceId}] @${username} fallback=rocket_api start`); } catch (_) {}
        const r = await fetchInstagramFollowersInfoRocketApi(username);
        if (r && r.success && r.profile) {
          profile = r.profile;
          source = String(profile.source || 'rocket_api');
          isPrivate = (typeof profile.isPrivate === 'boolean') ? profile.isPrivate : null;
          followersCount = (typeof profile.followersCount === 'number') ? profile.followersCount : null;
          error = null;
          if (typeof followersCount === 'number' && !(followersCount > 0)) {
            followersCount = null;
            error = 'invalid_followers_count';
          }
          hasFresh = !!(typeof followersCount === 'number' || typeof isPrivate === 'boolean');
          if (hasFresh) {
            try { console.log(`✅ [followers-mgmt:${traceId}] @${username} ok source=${source} private=${isPrivate === true ? '1' : (isPrivate === false ? '0' : '')} fc=${typeof followersCount === 'number' ? followersCount : ''} ms=${Date.now() - startedAtMs}`); } catch (_) {}
          }
        } else {
          const rErr = String((r && r.error) || 'unknown');
          const tag = `rocket_api:${rErr}`;
          if (!error) error = tag;
          else {
            const eStr = String(error || '');
            if (!eStr.includes(tag)) error = eStr ? (eStr + ' | ' + tag) : tag;
          }
          try { console.warn(`❌ [followers-mgmt:${traceId}] @${username} rocket_api fail error=${rErr}`); } catch (_) {}
        }
      } catch (e) {
        const tag = `rocket_api:${String(e?.message || e)}`;
        if (!error) error = tag;
        else {
          const eStr = String(error || '');
          if (!eStr.includes(tag)) error = eStr ? (eStr + ' | ' + tag) : tag;
        }
        try { console.warn(`❌ [followers-mgmt:${traceId}] @${username} rocket_api error:`, e?.message || String(e)); } catch (_) {}
      }
    }

    if (!hasFresh) {
      const prevFollowers = (cached && typeof cached.followersCount === 'number') ? cached.followersCount : null;
      const prevPrivate = (cached && typeof cached.isPrivate === 'boolean') ? cached.isPrivate : null;
      const prevCheckedAt = (cached && cached.checkedAt) ? cached.checkedAt : null;

      if (followersCount == null && prevFollowers != null) followersCount = prevFollowers;
      if (isPrivate == null && prevPrivate != null) isPrivate = prevPrivate;

      await monitorCol.updateOne(
        { username },
        { $set: { username, followersCount, isPrivate, source, error, lastAttemptAt: nowIso } },
        { upsert: true }
      );

      try { console.log(`🧊 [followers-mgmt:${traceId}] @${username} stale cached=${prevCheckedAt ? '1' : '0'} source=${source} private=${isPrivate === true ? '1' : (isPrivate === false ? '0' : '')} fc=${typeof followersCount === 'number' ? followersCount : ''} ms=${Date.now() - startedAtMs}`); } catch (_) {}
      return { code: 200, body: { ok: true, cached: !!prevCheckedAt, stale: true, username, followersCount, isPrivate, checkedAt: prevCheckedAt, source, error } };
    }

    // Detecção de privado no audit: quando a fonte primária trouxe os seguidores mas
    // NÃO o status de privado, consulta a profile API (187.124.91.24, self-hosted) e a
    // Rocket como reforço, só para resolver is_private. Evita conta privada passar sem flag.
    if (isPrivate == null) {
      try {
        const pa = await fetchInstagramProfileApiInfo(username);
        if (pa && pa.success && pa.profile && typeof pa.profile.isPrivate === 'boolean') {
          isPrivate = pa.profile.isPrivate;
          try { console.log(`🔒 [followers-mgmt:${traceId}] @${username} private-fill source=profile_api private=${isPrivate ? '1' : '0'}`); } catch (_) {}
        }
      } catch (_) {}
      if (isPrivate == null) {
        try {
          const rp = await fetchInstagramFollowersInfoRocketApi(username);
          if (rp && rp.success && rp.profile && typeof rp.profile.isPrivate === 'boolean') {
            isPrivate = rp.profile.isPrivate;
            try { console.log(`🔒 [followers-mgmt:${traceId}] @${username} private-fill source=rocket_api private=${isPrivate ? '1' : '0'}`); } catch (_) {}
          }
        } catch (_) {}
      }
    }

    const prevFollowersFinal = (cached && typeof cached.followersCount === 'number') ? cached.followersCount : null;
    if (followersCount == null && prevFollowersFinal != null && prevFollowersFinal > 0) followersCount = prevFollowersFinal;

    await monitorCol.updateOne(
      { username },
      { $set: { username, followersCount, isPrivate, checkedAt: nowIso, source, error, lastAttemptAt: nowIso } },
      { upsert: true }
    );

    try { console.log(`📌 [followers-mgmt:${traceId}] @${username} saved source=${source} private=${isPrivate === true ? '1' : (isPrivate === false ? '0' : '')} fc=${typeof followersCount === 'number' ? followersCount : ''} ms=${Date.now() - startedAtMs}`); } catch (_) {}
    return { code: 200, body: { ok: true, cached: false, username, followersCount, isPrivate, checkedAt: nowIso, source, error } };
  });
};

app.post('/api/painel/gerenciamento-seguidores/settings', requireAdmin, async (req, res) => {
  try {
    const dailyLimitRaw = parseInt(String((req.body && req.body.dailyLimit) || '50'), 10);
    const dailyLimit = Math.min(1000, Math.max(1, Number.isFinite(dailyLimitRaw) ? dailyLimitRaw : 50));
    const orderRaw = String((req.body && req.body.order) || 'newest').trim().toLowerCase();
    const order = (orderRaw === 'oldest') ? 'oldest' : 'newest';

    const { getCollection } = require('./mongodbClient');
    const settingsCol = await getCollection('settings');
    await settingsCol.updateOne(
      { _id: 'followers_mgmt_settings' },
      { $set: { values: { dailyLimit, order }, updatedAt: new Date().toISOString() } },
      { upsert: true }
    );
    return res.json({ ok: true, dailyLimit, order });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.get('/api/painel/gerenciamento-seguidores/current', requireAdmin, async (req, res) => {
  try {
    const username = String(req.query.username || '').trim().toLowerCase().replace(/^@/, '');
    const force = String(req.query.force || '').trim() === '1';
    if (!username) return res.status(400).json({ ok: false, error: 'missing_username' });

    const out = await followersMgmtGetCurrent(req, username, force);
    return res.status(out.code).json(out.body);
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

async function followersMgmtComputeAutoNotifyCandidates({ limit, order }) {
  const limitRaw = parseInt(String(limit || '0'), 10);
  const lim = Math.max(0, Math.min(5000, Number.isFinite(limitRaw) ? limitRaw : 0));
  const orderRaw = String(order || 'recent').trim().toLowerCase();
  const ord = (orderRaw === 'oldest') ? 'oldest' : 'recent';
  const safe = (v) => String(v == null ? '' : v).trim();
  const brtOffsetMs = 3 * 60 * 60 * 1000;
  const dayKeyBrt = (ms) => {
    const d = new Date(Number(ms || 0) - brtOffsetMs);
    const y = String(d.getUTCFullYear());
    const m = String(d.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(d.getUTCDate()).padStart(2, '0');
    return `${y}-${m}-${dd}`;
  };
  const dayRangeBrtUtcMs = (dayKey) => {
    try {
      const s = String(dayKey || '').trim();
      if (!/^\d{4}-\d{2}-\d{2}$/.test(s)) return { startMs: 0, endMs: 0 };
      const parts = s.split('-').map(Number);
      const y = parts[0];
      const m = parts[1];
      const d = parts[2];
      const startUtcMs = Date.UTC(y, m - 1, d, 0, 0, 0, 0) + brtOffsetMs;
      const endUtcMs = startUtcMs + (24 * 60 * 60 * 1000);
      return { startMs: startUtcMs, endMs: endUtcMs };
    } catch (_) {
      return { startMs: 0, endMs: 0 };
    }
  };

  const { getCollection } = require('./mongodbClient');
  const col = await getCollection('checkout_orders');
  const monitorCol = await getCollection('followers_monitor');
  const validatedCol = await getCollection('validated_insta_users');

  const stats = {
    monitorDocs: 0,
    monitorUsable: 0,
    monitorSkippedNoFollowers: 0,
    monitorSkippedNoCheckedAt: 0,
    validatedDocs: 0,
    validatedUsable: 0,
    validatedSkippedNoFollowers: 0,
    validatedSkippedNoCheckedAt: 0,
    ordersScanned: 0,
    ordersSkippedNoUsername: 0,
    ordersSkippedNoMonitor: 0,
    ordersSkippedPrivate: 0,
    ordersSkippedOrganicos: 0,
    ordersLatestByUser: 0,
    candidatesScanned: 0,
    candidatesSkippedMissingQtyOrInitial: 0,
    candidatesSkippedNoCurrent: 0,
    candidatesSkippedDropBelow100: 0,
    candidatesSkippedAlreadyNotified: 0,
    candidatesStage0FirstEmail: 0,
    candidatesStage1SecondEmail: 0,
    candidatesStage1SkippedNoNewCheck: 0,
    eligible: 0
  };

  const todayBrtKey = dayKeyBrt(Date.now());
  const { startMs: todayStartMs, endMs: todayEndMs } = dayRangeBrtUtcMs(todayBrtKey);
  const toIso = (ms) => (Number.isFinite(ms) && ms > 0) ? new Date(ms).toISOString() : '';
  const todayStartIso = toIso(todayStartMs);
  const todayEndIso = toIso(todayEndMs);
  const dailyMaxRaw = parseInt(String(process.env.RECOVERY_EMAIL_DAILY_LIMIT || process.env.EMAIL_DAILY_LIMIT || '1000'), 10);
  const dailyMax = Math.max(1, Number.isFinite(dailyMaxRaw) ? dailyMaxRaw : 1000);
  const reservePctRaw = Number(String(process.env.RECOVERY_EMAIL_RESERVE_PCT || '0.2'));
  const reservePct = (Number.isFinite(reservePctRaw) && reservePctRaw >= 0 && reservePctRaw <= 0.9) ? reservePctRaw : 0.2;
  let paidEmailCountToday = 0;
  let createdEmailCountToday = 0;
  let recoveryEmailSentEventsToday = 0;
  let recoveryEmailSentOrdersToday = 0;
  try {
    if (todayStartIso && todayEndIso) {
      paidEmailCountToday = await col.countDocuments({
        $or: [
          { 'woovi.paidAt': { $gte: todayStartIso, $lt: todayEndIso } },
          { paidAt: { $gte: todayStartIso, $lt: todayEndIso } }
        ]
      });
      createdEmailCountToday = await col.countDocuments({
        createdAt: { $gte: todayStartIso, $lt: todayEndIso }
      });
      const agg = await col.aggregate([
        { $match: { 'recoveryNotify.email.history': { $exists: true, $ne: [] } } },
        { $unwind: '$recoveryNotify.email.history' },
        { $match: { 'recoveryNotify.email.history.status': 'sent', 'recoveryNotify.email.history.at': { $gte: todayStartIso, $lt: todayEndIso } } },
        { $count: 'c' }
      ]).toArray();
      recoveryEmailSentEventsToday = agg && agg[0] && typeof agg[0].c === 'number' ? agg[0].c : 0;
      const agg2 = await col.aggregate([
        { $match: { 'recoveryNotify.email.history': { $exists: true, $ne: [] } } },
        { $unwind: '$recoveryNotify.email.history' },
        { $match: { 'recoveryNotify.email.history.status': 'sent', 'recoveryNotify.email.history.at': { $gte: todayStartIso, $lt: todayEndIso } } },
        { $group: { _id: '$_id' } },
        { $count: 'c' }
      ]).toArray();
      recoveryEmailSentOrdersToday = agg2 && agg2[0] && typeof agg2[0].c === 'number' ? agg2[0].c : 0;
    }
  } catch (_) {}
  const pedidosEmailCountToday = Math.max(0, Number(paidEmailCountToday || 0) + Number(createdEmailCountToday || 0));
  const availableAfterPedidos = Math.max(0, dailyMax - pedidosEmailCountToday);
  const allowedForRecoveryToday = Math.max(0, Math.floor(availableAfterPedidos * (1 - reservePct)));
  const remainingRecoveryToday = Math.max(0, allowedForRecoveryToday - Number(recoveryEmailSentEventsToday || 0));

  const parseDateMsLoose = (raw) => {
    try {
      const s0 = String(raw || '').trim();
      if (!s0) return 0;
      const s = s0.replace(',', ' ').replace(/\s+/g, ' ').trim();
      const mBr = s.match(/(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2})(?::(\d{2}))?)?/);
      if (mBr) {
        const yyyy = String(mBr[3]);
        const mm = String(mBr[2]).padStart(2, '0');
        const dd = String(mBr[1]).padStart(2, '0');
        const hh = String(mBr[4] || '00').padStart(2, '0');
        const mi = String(mBr[5] || '00').padStart(2, '0');
        const ss = String(mBr[6] || '00').padStart(2, '0');
        const iso = `${yyyy}-${mm}-${dd}T${hh}:${mi}:${ss}-03:00`;
        const t = new Date(iso).getTime();
        return Number.isFinite(t) ? t : 0;
      }
      const t = new Date(s).getTime();
      return Number.isFinite(t) ? t : 0;
    } catch (_) {
      return 0;
    }
  };

  const monDocs = await monitorCol.find(
    { checkedAt: { $exists: true, $ne: '' }, hidden: { $ne: true } },
    { projection: { _id: 0, username: 1, followersCount: 1, checkedAt: 1, hidden: 1 } }
  ).limit(50000).toArray();

  const vuDocs = await validatedCol.find(
    { checkedAt: { $exists: true, $ne: '' } },
    { projection: { _id: 0, username: 1, followersCount: 1, checkedAt: 1 } }
  ).limit(50000).toArray();

  const monByUser = new Map();
  stats.monitorDocs = Array.isArray(monDocs) ? monDocs.length : 0;
  for (const m of (monDocs || [])) {
    const u = safe(m && m.username).toLowerCase().replace(/^@/, '');
    if (!u) continue;
    const checkedAtMs = parseDateMsLoose(m && m.checkedAt);
    const followersCount = (typeof m?.followersCount === 'number') ? m.followersCount : null;
    if (!checkedAtMs) { stats.monitorSkippedNoCheckedAt += 1; continue; }
    if (followersCount == null) { stats.monitorSkippedNoFollowers += 1; continue; }
    stats.monitorUsable += 1;
    const prev = monByUser.get(u);
    if (!prev || Number(checkedAtMs || 0) >= Number(prev.checkedAtMs || 0)) {
      monByUser.set(u, { checkedAtMs, followersCount });
    }
  }
  stats.validatedDocs = Array.isArray(vuDocs) ? vuDocs.length : 0;
  for (const v of (vuDocs || [])) {
    const u = safe(v && v.username).toLowerCase().replace(/^@/, '');
    if (!u) continue;
    const checkedAtMs = parseDateMsLoose(v && v.checkedAt);
    const followersCount = (typeof v?.followersCount === 'number') ? v.followersCount : null;
    if (!checkedAtMs) { stats.validatedSkippedNoCheckedAt += 1; continue; }
    if (followersCount == null) { stats.validatedSkippedNoFollowers += 1; continue; }
    stats.validatedUsable += 1;
    const prev = monByUser.get(u);
    if (!prev || Number(checkedAtMs || 0) >= Number(prev.checkedAtMs || 0)) {
      monByUser.set(u, { checkedAtMs, followersCount });
    }
  }
  if (!monByUser.size) return { ok: true, total: 0, candidates: [], emailBudget: null, stats };

  const vuByUser = new Map();
  for (const v of (vuDocs || [])) {
    const u = safe(v && v.username).toLowerCase().replace(/^@/, '');
    if (!u) continue;
    const followersCount = (typeof v?.followersCount === 'number') ? v.followersCount : null;
    if (followersCount == null) continue;
    vuByUser.set(u, { followersCount, checkedAtMs: parseDateMsLoose(v && v.checkedAt) });
  }

  const followersQuery = {
    $and: [
      {
        $or: [
          { status: 'paid' },
          { paymentStatus: 'paid' },
          { paymentStatus: 'approved' },
          { paymentStatus: 'succeeded' },
          { paymentStatus: 'received' },
          { 'woovi.status': { $in: ['PAID', 'COMPLETED'] } },
          { paidAt: { $exists: true, $ne: null } },
          { 'woovi.paidAt': { $exists: true, $ne: null } }
        ]
      },
      {
        $or: [
          { categoria_servico: { $regex: '^seguidores$', $options: 'i' } },
          { 'additionalInfoMapPaid.categoria_servico': { $regex: '^seguidores$', $options: 'i' } },
          { 'additionalInfoMap.categoria_servico': { $regex: '^seguidores$', $options: 'i' } },
          { tipo: { $regex: 'seguidores', $options: 'i' } },
          { tipoServico: { $regex: 'seguidores', $options: 'i' } }
        ]
      }
    ]
  };
  const ordersCursor = col.find(followersQuery, {
    projection: {
      _id: 1, createdAt: 1, paidAt: 1, woovi: 1, tipo: 1, tipoServico: 1, qtd: 1, quantidade: 1,
      instagramUsername: 1, instauser: 1, initialFollowersCount: 1, isPrivate: 1, profilePrivacy: 1,
      additionalInfo: 1, additionalInfoPaid: 1, additionalInfoMap: 1, additionalInfoMapPaid: 1,
      recoveryNotify: 1
    }
  }).sort({ createdAt: -1 }).limit(50000);

  const getMapObj = (o, k) => {
    try {
      if (o?.additionalInfoMapPaid && typeof o.additionalInfoMapPaid[k] !== 'undefined') return o.additionalInfoMapPaid[k];
      if (o?.additionalInfoMap && typeof o.additionalInfoMap[k] !== 'undefined') return o.additionalInfoMap[k];
    } catch (_) {}
    return undefined;
  };
  const getArrVal = (arr, key) => {
    try {
      const a = Array.isArray(arr) ? arr : [];
      const it = a.find(x => x && safe(x.key).toLowerCase() === String(key || '').toLowerCase());
      return it && typeof it.value !== 'undefined' ? it.value : undefined;
    } catch (_) { return undefined; }
  };
  const pick = (o, key) => {
    const a = getMapObj(o, key);
    if (typeof a !== 'undefined') return a;
    const b = getArrVal(o?.additionalInfoPaid, key);
    if (typeof b !== 'undefined') return b;
    const c = getArrVal(o?.additionalInfo, key);
    if (typeof c !== 'undefined') return c;
    return undefined;
  };
  const resolveUsername = (o) => {
    const u = safe(o?.instagramUsername || o?.instauser || pick(o, 'instagram_username') || pick(o, 'instauser')).toLowerCase();
    return u.replace(/^@/, '').replace(/\/+$/, '').split('/').pop().trim();
  };
  const resolveDateMs = (o) => {
    const t = new Date(o?.woovi?.paidAt || o?.paidAt || o?.createdAt || 0).getTime();
    return Number.isFinite(t) ? t : 0;
  };
  const isPrivateOrder = (o) => {
    const a = o?.isPrivate;
    const b = o?.profilePrivacy;
    const c = pick(o, 'isPrivate');
    return a === true || b === true || String(c || '').toLowerCase() === 'true';
  };

  const latestByUser = new Map();
  for await (const o of ordersCursor) {
    stats.ordersScanned += 1;
    const u = resolveUsername(o);
    if (!u) { stats.ordersSkippedNoUsername += 1; continue; }
    if (!monByUser.has(u)) { stats.ordersSkippedNoMonitor += 1; continue; }
    const tipoRaw = safe(o?.tipoServico || o?.tipo || pick(o, 'tipo_servico')).toLowerCase();
    if (tipoRaw && /seguidores_organicos|organicos/.test(tipoRaw)) { stats.ordersSkippedOrganicos += 1; continue; }
    if (isPrivateOrder(o)) stats.ordersSkippedPrivate += 1;
    const ms = resolveDateMs(o);
    const prev = latestByUser.get(u);
    if (!prev || ms > prev.ms) latestByUser.set(u, { ms, order: o });
  }
  stats.ordersLatestByUser = latestByUser.size;

  const out = [];
  for (const [u, rec] of latestByUser.entries()) {
    stats.candidatesScanned += 1;
    const o = rec.order;
    const mon = monByUser.get(u);
    if (!o || !mon) continue;
    const qty = Number(o?.qtd || o?.quantidade || pick(o, 'quantidade') || pick(o, 'qtd') || pick(o, 'quantity') || 0) || 0;
    const initialRaw = (typeof o?.initialFollowersCount === 'number')
      ? o.initialFollowersCount
      : Number(pick(o, 'start_count') || pick(o, 'initial_followers') || pick(o, 'inicial') || 0) || 0;
    const initial = (initialRaw > 0)
      ? initialRaw
      : (() => {
        const vu = vuByUser.get(u);
        if (vu && typeof vu.followersCount === 'number' && vu.followersCount > 0) return vu.followersCount;
        if (typeof mon.followersCount === 'number' && mon.followersCount > 0) return mon.followersCount;
        return 0;
      })();
    if (!(qty > 0 && initial > 0)) { stats.candidatesSkippedMissingQtyOrInitial += 1; continue; }
    const expected = initial + qty;
    const current = mon.followersCount;
    if (current == null) { stats.candidatesSkippedNoCurrent += 1; continue; }
    const dropAbs = Math.max(0, expected - current);
    if (!(current < expected)) { stats.candidatesSkippedDropBelow100 += 1; continue; }
    if (dropAbs < 100) { stats.candidatesSkippedDropBelow100 += 1; continue; }

    const notify = (o && o.recoveryNotify && typeof o.recoveryNotify === 'object') ? o.recoveryNotify : {};
    const nEmail = (notify && notify.email && typeof notify.email === 'object') ? notify.email : {};
    const nSms = (notify && notify.sms && typeof notify.sms === 'object') ? notify.sms : {};
    const emailOk = String(nEmail.lastStatus || '').trim().toLowerCase() === 'sent';
    const smsOk = !!safe(nSms.sentAt);
    const emailHist = (Array.isArray(nEmail.history) ? nEmail.history : []);
    const hasEmailHistory = emailHist.length > 0;
    let emailSentCountFromHist = 0;
    let lastEmailSentAtMs = 0;
    for (const h of emailHist) {
      try {
        if (!h || typeof h !== 'object') continue;
        const st = String(h.status || '').trim().toLowerCase();
        if (st !== 'sent') continue;
        emailSentCountFromHist += 1;
        const atMs = parseDateMsLoose(h.at || h.sentAt || h.lastSentAt || h.lastAttemptAt || '');
        if (atMs && atMs > lastEmailSentAtMs) lastEmailSentAtMs = atMs;
      } catch (_) {}
    }
    const fallbackEmailAtMs = parseDateMsLoose(nEmail.lastSentAt || nEmail.lastAttemptAt || nEmail.sentAt || '');
    if (!lastEmailSentAtMs && fallbackEmailAtMs) lastEmailSentAtMs = fallbackEmailAtMs;

    const emailSentCount = Math.max(emailSentCountFromHist, emailOk ? 1 : 0);
    const checkedAtMs = Number(mon.checkedAtMs || 0) || 0;
    const hasNewCheckSinceEmail = (!!lastEmailSentAtMs && checkedAtMs > lastEmailSentAtMs);

    let stage = 0;
    if (emailSentCount <= 0) stage = 0;
    else if (emailSentCount === 1) {
      if (!hasNewCheckSinceEmail) { stats.candidatesStage1SkippedNoNewCheck += 1; continue; }
      stage = 1;
    } else {
      stats.candidatesSkippedAlreadyNotified += 1;
      continue;
    }
    if (stage === 0) stats.candidatesStage0FirstEmail += 1;
    if (stage === 1) stats.candidatesStage1SecondEmail += 1;

    out.push({ orderId: String(o._id), username: u, checkedAtMs, dropAbs, stage, emailSentCount, lastEmailSentAtMs, hasEmailHistory, smsOk });
  }
  stats.eligible = out.length;

  out.sort((a, b) => {
    const sa = Number(a.stage || 0);
    const sb = Number(b.stage || 0);
    if (sa !== sb) return sa - sb;
    const ha = a.hasEmailHistory ? 1 : 0;
    const hb = b.hasEmailHistory ? 1 : 0;
    if (ha !== hb) return ha - hb;
    const ca = Number(a.checkedAtMs || 0);
    const cb = Number(b.checkedAtMs || 0);
    if (ca !== cb) return ord === 'oldest' ? (ca - cb) : (cb - ca);
    const da = Number(a.dropAbs || 0);
    const db = Number(b.dropAbs || 0);
    if (da !== db) return db - da;
    return 0;
  });
  const dailyCap = remainingRecoveryToday > 0 ? remainingRecoveryToday : 0;
  const capLimit = dailyCap > 0 ? dailyCap : 0;
  const maxCandidates = (lim > 0 && capLimit > 0) ? Math.min(lim, capLimit) : (lim > 0 ? lim : (capLimit > 0 ? capLimit : 0));
  const sliced = maxCandidates > 0 ? out.slice(0, maxCandidates) : out;

  return {
    ok: true,
    total: out.length,
    candidates: sliced,
    emailBudget: {
      todayBrtKey,
      dailyMax,
      reservePct,
      paidEmailCountToday,
      createdEmailCountToday,
      pedidosEmailCountToday,
      availableAfterPedidos,
      allowedForRecoveryToday,
      recoveryEmailSentEventsToday,
      recoveryEmailSentOrdersToday,
      remainingRecoveryToday
    },
    stats
  };
}

