app.post('/api/painel/gerenciamento-seguidores/fix-checked', requireAdmin, async (req, res) => {
  try {
    const raw = (req.body && (req.body.items || req.body.rows || req.body.targets)) || [];
    const arr = Array.isArray(raw) ? raw : [raw];
    const items = arr
      .map(x => ({
        username: String(x && x.username ? x.username : x).trim().toLowerCase().replace(/^@/, ''),
        purchaseAtMs: Number(x && x.purchaseAtMs ? x.purchaseAtMs : 0) || 0
      }))
      .filter(x => x.username);

    const dedup = new Map();
    for (const it of items) {
      if (!dedup.has(it.username)) dedup.set(it.username, it);
    }
    const list = Array.from(dedup.values()).slice(0, 2000);
    if (!list.length) return res.status(400).json({ ok: false, error: 'missing_usernames' });

    const { getCollection } = require('./mongodbClient');
    const monitorCol = await getCollection('followers_monitor');
    const docs = await monitorCol
      .find({ username: { $in: list.map(x => x.username) } }, { projection: { username: 1, checkedAt: 1 } })
      .toArray();
    const byUser = new Map(docs.map(d => [String(d.username || '').toLowerCase(), d]));

    const ops = [];
    const fixed = [];
    const skipped = [];
    const parseDateMsLoose = (raw) => {
      try {
        const s0 = String(raw || '').trim();
        if (!s0) return 0;
        const s = s0.replace(',', ' ').replace(/\s+/g, ' ').trim();
        const mBr = s.match(/(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2})(?::(\d{2}))?)?/);
        if (mBr) {
          const yyyy = String(mBr[3]);
          const mm = String(mBr[2]).padStart(2, '0');
          const dd = String(mBr[1]).padStart(2, '0');
          const hh = String(mBr[4] || '00').padStart(2, '0');
          const mi = String(mBr[5] || '00').padStart(2, '0');
          const ss = String(mBr[6] || '00').padStart(2, '0');
          const iso = `${yyyy}-${mm}-${dd}T${hh}:${mi}:${ss}-03:00`;
          const t = new Date(iso).getTime();
          return Number.isFinite(t) ? t : 0;
        }
        const t = new Date(s).getTime();
        return Number.isFinite(t) ? t : 0;
      } catch (_) {
        return 0;
      }
    };
    const dayMs = 24 * 60 * 60 * 1000;
    const brtOffsetMs = 3 * 60 * 60 * 1000;
    const dayNumFromMsBrt = (ms) => {
      const d = new Date(Number(ms || 0) - brtOffsetMs);
      return Math.floor(Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate()) / dayMs);
    };

    for (const it of list) {
      const doc = byUser.get(it.username) || null;
      const checkedAt = doc && doc.checkedAt ? String(doc.checkedAt) : '';
      let checkedAtMs = 0;
      try {
        if (checkedAt) {
          checkedAtMs = parseDateMsLoose(checkedAt);
        }
      } catch (_) {}
      if (!checkedAtMs || !it.purchaseAtMs) {
        skipped.push(it.username);
        continue;
      }
      const checkedDay = dayNumFromMsBrt(checkedAtMs);
      const purchaseDay = dayNumFromMsBrt(it.purchaseAtMs);
      if (checkedDay > purchaseDay) {
        skipped.push(it.username);
        continue;
      }
      ops.push({
        updateOne: {
          filter: { username: it.username },
          update: { $unset: { checkedAt: '', followersCount: '', source: '', error: '', isPrivate: '' } },
          upsert: false
        }
      });
      fixed.push(it.username);
    }

    if (ops.length) {
      await monitorCol.bulkWrite(ops, { ordered: false });
    }
    return res.json({ ok: true, fixedCount: fixed.length, fixed, skippedCount: skipped.length });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.get('/api/painel/gerenciamento-seguidores/ig-profiles', requireAdmin, async (req, res) => {
  try {
    const profiles = Array.isArray(cookieProfiles) ? cookieProfiles : [];
    const mask = (v, left, right) => {
      const s = String(v || '');
      const l = Math.max(0, Number(left || 0));
      const r = Math.max(0, Number(right || 0));
      if (!s) return '';
      if (s.length <= (l + r + 2)) return s.slice(0, Math.min(s.length, l)) + '…';
      return s.slice(0, l) + '…' + s.slice(Math.max(0, s.length - r));
    };
    const out = profiles.map(p => ({
      ds_user_id: mask(p && p.ds_user_id, 4, 3),
      sessionid: mask(p && p.sessionid, 6, 4),
      hasProxy: !!(p && p.proxy && p.proxy.host && p.proxy.port),
      errorCount: Number(p && p.errorCount || 0) || 0,
      disabledUntil: Number(p && p.disabledUntil || 0) || 0,
      lastUsed: Number(p && p.lastUsed || 0) || 0
    }));
    return res.json({ ok: true, count: out.length, profiles: out });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

