function followersMgmtSerializeFixInitialJob(jobRaw) {
  const job = jobRaw || null;
  if (!job) return null;
  return {
    id: job.id,
    status: job.status,
    startedAt: job.startedAt,
    finishedAt: job.finishedAt,
    total: job.total,
    done: job.done,
    ok: job.ok,
    failed: job.failed,
    skipped: job.skipped,
    lastUsername: job.lastUsername || null,
    lastError: job.lastError || null
  };
}

function followersMgmtKickFixInitialJob() {
  const job = global.followersMgmtFixInitialJob || null;
  if (!job) return;
  if (job._runnerActive) return;
  if (job.status !== 'running') return;
  job._runnerActive = true;

  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
  const isTlsishError = (e) => {
    try {
      const code = String(e?.code || '').trim().toUpperCase();
      const msg = String(e?.message || String(e) || '').toLowerCase();
      if (code === 'CERT_HAS_EXPIRED' || code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE' || code === 'DEPTH_ZERO_SELF_SIGNED_CERT') return true;
      return /certificate|ssl|tls|handshake/i.test(msg);
    } catch (_) {
      return false;
    }
  };
  const isTimeoutishError = (e) => {
    try {
      const code = String(e?.code || '').trim().toUpperCase();
      const msg = String(e?.message || String(e) || '').toLowerCase();
      if (code === 'ECONNABORTED' || code === 'ETIMEDOUT' || code === 'ECONNRESET') return true;
      return /timeout/i.test(msg);
    } catch (_) {
      return false;
    }
  };
  const toIsoFromProvider = (raw) => {
    try {
      const s0 = String(raw || '').trim();
      if (!s0) return null;
      const m = s0.match(/^(\d{4})-(\d{2})-(\d{2})(?:\s+(\d{2}):(\d{2})(?::(\d{2}))?)?$/);
      if (m) {
        const y = m[1], mo = m[2], d = m[3];
        const hh = m[4] || '00', mi = m[5] || '00', ss = m[6] || '00';
        const iso = `${y}-${mo}-${d}T${hh}:${mi}:${ss}-03:00`;
        const t = new Date(iso).getTime();
        if (Number.isFinite(t) && t > 0) return new Date(t).toISOString();
      }
      const t2 = new Date(s0).getTime();
      if (Number.isFinite(t2) && t2 > 0) return new Date(t2).toISOString();
      return null;
    } catch (_) {
      return null;
    }
  };
  const normalizeUsername = (u) => String(u || '').trim().replace(/^@+/, '').toLowerCase();
  const apiProxyUrl = (username) => {
    const base = 'https://www.refilfama24h.com/api_proxy.php?link=';
    const u = `https://instagram.com/${encodeURIComponent(normalizeUsername(username))}`;
    return base + encodeURIComponent(u);
  };
  const fetchPedidoByUser = async (username) => {
    const url = apiProxyUrl(username);
    try {
      const resp = await axios.get(url, { timeout: 30000, validateStatus: () => true, family: 4, headers: { 'Accept': 'application/json' } });
      return resp;
    } catch (e) {
      if ((isTlsishError(e) || isTimeoutishError(e)) && /^https:\/\//i.test(url)) {
        const httpUrl = url.replace(/^https:/i, 'http:');
        return await axios.get(httpUrl, { timeout: 30000, validateStatus: () => true, family: 4, headers: { 'Accept': 'application/json' } });
      }
      throw e;
    }
  };

  (async () => {
    try {
      const { getCollection } = require('./mongodbClient');
      const ordersCol = await getCollection('checkout_orders');
      let ObjectId = null;
      try { ({ ObjectId } = require('mongodb')); } catch (_) { ObjectId = null; }

      const apiProxyCache = new Map();
      const safeJsonResponse = (data) => {
        try {
          if (data == null) return null;
          if (typeof data === 'object') return data;
          if (typeof data === 'string') {
            const s = String(data || '').trim();
            if (!s) return null;
            if (s.startsWith('{') || s.startsWith('[')) {
              try { return JSON.parse(s); } catch (_) { return { raw: s }; }
            }
            return { raw: s };
          }
          return { raw: String(data) };
        } catch (_) {
          return null;
        }
      };
      const fetchApiProxyListByUser = async (username) => {
        const u = normalizeUsername(username);
        if (!u) return [];
        if (apiProxyCache.has(u)) return apiProxyCache.get(u) || [];
        const resp = await fetchPedidoByUser(u);
        const body = safeJsonResponse(resp && resp.data);
        const first = Array.isArray(body) ? body[0] : body;
        const list = first && first.data && Array.isArray(first.data.list) ? first.data.list : [];
        apiProxyCache.set(u, Array.isArray(list) ? list : []);
        return apiProxyCache.get(u) || [];
      };
      const toInt = (v) => {
        try {
          if (typeof v === 'number' && Number.isFinite(v)) return Math.trunc(v);
          const s0 = String(v == null ? '' : v).trim();
          if (!s0) return 0;
          const s = s0.replace(/\s+/g, '');
          if (/^\d{1,3}(\.\d{3})+(,\d+)?$/.test(s)) return Math.trunc(Number(s.replace(/\./g, '').replace(',', '.')));
          if (/^\d{1,3}(,\d{3})+(\.\d+)?$/.test(s)) return Math.trunc(Number(s.replace(/,/g, '')));
          if (/^\d+(\.\d{3})+$/.test(s)) return Math.trunc(Number(s.replace(/\./g, '')));
          if (/^\d+(,\d{3})+$/.test(s)) return Math.trunc(Number(s.replace(/,/g, '')));
          const n0 = Number(s);
          if (Number.isFinite(n0)) return Math.trunc(n0);
          const digits = s0.replace(/[^\d\-]/g, '');
          if (!digits) return 0;
          const n1 = Number(digits);
          return Number.isFinite(n1) ? Math.trunc(n1) : 0;
        } catch (_) {
          return 0;
        }
      };
      const pickAdd = (doc, key) => {
        try {
          const mapPaid = (doc && doc.additionalInfoMapPaid && typeof doc.additionalInfoMapPaid === 'object') ? doc.additionalInfoMapPaid : {};
          const map = (doc && doc.additionalInfoMap && typeof doc.additionalInfoMap === 'object') ? doc.additionalInfoMap : {};
          if (typeof mapPaid[key] !== 'undefined') return mapPaid[key];
          if (typeof map[key] !== 'undefined') return map[key];
          const arrPaid = Array.isArray(doc && doc.additionalInfoPaid) ? doc.additionalInfoPaid : [];
          const itPaid = arrPaid.find(x => x && String(x.key || '').trim() === key);
          if (itPaid && typeof itPaid.value !== 'undefined') return itPaid.value;
          const arr = Array.isArray(doc && doc.additionalInfo) ? doc.additionalInfo : [];
          const it = arr.find(x => x && String(x.key || '').trim() === key);
          if (it && typeof it.value !== 'undefined') return it.value;
        } catch (_) {}
        return '';
      };
      const resolveContractedQty = (doc) => {
        try {
          if (typeof doc?.quantidade === 'number' && Number.isFinite(doc.quantidade)) return Math.trunc(doc.quantidade);
          if (typeof doc?.qtd === 'number' && Number.isFinite(doc.qtd)) return Math.trunc(doc.qtd);
          const q0 = toInt(pickAdd(doc, 'quantidade'));
          return q0 > 0 ? q0 : 0;
        } catch (_) {
          return 0;
        }
      };
      const resolveProviderServiceId = (doc) => {
        try {
          const candidates = [
            doc?.fama24h?.requestPayload?.service,
            doc?.fornecedor_social?.requestPayload?.service,
            pickAdd(doc, 'service'),
            pickAdd(doc, 'service_id'),
            pickAdd(doc, 'serviceId')
          ];
          for (const c of candidates) {
            const n = toInt(c);
            if (n > 0) return n;
          }
        } catch (_) {}
        return 0;
      };
      const resolveProviderOrderIdFromOrderDoc = (doc) => {
        try {
          const candidates = [
            doc?.fama24h?.orderId,
            doc?.fama24h?.orderID,
            doc?.fama24h?.order_id,
            doc?.fornecedor_social?.orderId,
            doc?.fornecedor_social?.orderID,
            doc?.fornecedor_social?.order_id
          ];
          for (const c of candidates) {
            const s = String(c == null ? '' : c).trim();
            if (s) return s;
          }
          const multi = Array.isArray(doc?.fama24h_multi?.orders) ? doc.fama24h_multi.orders : [];
          for (const it of multi) {
            const s = String(it?.orderId || it?.orderID || it?.order_id || '').trim();
            if (s) return s;
          }
        } catch (_) {}
        return '';
      };
      const resolvePurchaseAtMsFromOrderDoc = (doc) => {
        const toMs = (v) => {
          try {
            if (!v) return 0;
            const t = new Date(String(v)).getTime();
            return Number.isFinite(t) ? t : 0;
          } catch (_) {
            return 0;
          }
        };
        try {
          const paidMs = Math.max(
            toMs(doc?.woovi?.paidAt),
            toMs(doc?.paghiper?.paidAt),
            toMs(doc?.payment?.paidAt),
            toMs(doc?.expay?.paidAt),
            toMs(doc?.paidAt)
          );
          if (paidMs > 0) return paidMs;
        } catch (_) {}
        try {
          const createdMs = toMs(doc?.createdAt);
          if (createdMs > 0) return createdMs;
        } catch (_) {}
        return 0;
      };
      const scorePedidoMatch = (pedido, want) => {
        try {
          if (!pedido || typeof pedido !== 'object') return -1;
          const pStart = toInt(pedido.start_count);
          if (!(pStart > 0)) return -1;
          const pQty = toInt(pedido.quantity);
          const pService = toInt(pedido.service_id || pedido.service);
          let score = 0;
          if (want.fornecedorOrderId && String(pedido.id || '').trim() === want.fornecedorOrderId) score += 1000;
          if (want.serviceId && pService && pService === want.serviceId) score += 50;
          if (want.qty && pQty && pQty === want.qty) score += 30;
          if (want.purchaseAtMs) {
            const createdIso = toIsoFromProvider(pedido.created_at || pedido.created || '') || null;
            const t = createdIso ? new Date(createdIso).getTime() : 0;
            if (Number.isFinite(t) && t > 0) {
              const diff = Math.abs(t - Number(want.purchaseAtMs));
              if (diff <= (6 * 60 * 60 * 1000)) score += 20;
              else if (diff <= (24 * 60 * 60 * 1000)) score += 8;
              else if (diff <= (72 * 60 * 60 * 1000)) score += 3;
            }
          }
          return score;
        } catch (_) {
          return -1;
        }
      };

      const targets = Array.isArray(job.targets) ? job.targets : [];
      while (job.status === 'running' && job.done < targets.length) {
        const t = targets[job.done] || {};
        const username = normalizeUsername(t.username || '');
        job.lastUsername = username || null;
        job.lastError = null;
        try {
          const fornecedorOrderId = String(t.fornecedorOrderId || '').trim();
          const orderIdRaw = String(t.orderId || '').trim();
          if (!username || !orderIdRaw) {
            job.skipped += 1;
            job.done += 1;
            continue;
          }

          const filter = (() => {
            if (ObjectId && /^[0-9a-fA-F]{24}$/.test(orderIdRaw)) {
              try { return { _id: new ObjectId(orderIdRaw) }; } catch (_) {}
            }
            return { _id: orderIdRaw };
          })();
          const orderDoc = await ordersCol.findOne(
            filter,
            { projection: { _id: 1, quantidade: 1, qtd: 1, tipo: 1, tipoServico: 1, additionalInfoMapPaid: 1, additionalInfoPaid: 1, additionalInfoMap: 1, additionalInfo: 1, fama24h: 1, fama24h_multi: 1, fornecedor_social: 1, woovi: 1, paghiper: 1, payment: 1, expay: 1, paidAt: 1, createdAt: 1 } }
          );
          const isEligibleTipo = (() => {
            try {
              const tipoRaw = String(
                (t && t.tipo) ||
                (orderDoc && (orderDoc.tipo || orderDoc.tipoServico)) ||
                pickAdd(orderDoc, 'tipo') ||
                pickAdd(orderDoc, 'tipo_servico') ||
                ''
              ).toLowerCase();
              if (!tipoRaw) return false;
              if (tipoRaw.includes('curtida') || tipoRaw.includes('like')) return false;
              if (tipoRaw.includes('visualiza') || tipoRaw.includes('view')) return false;
              if (tipoRaw.includes('organ')) return false;
              return (tipoRaw.includes('misto') || tipoRaw.includes('brasileir'));
            } catch (_) {
              return false;
            }
          })();
          if (!isEligibleTipo) {
            job.skipped += 1;
            job.done += 1;
            continue;
          }
          let purchaseAtMs = Number(t.purchaseAtMs || 0) || 0;
          if (!(purchaseAtMs > 0)) purchaseAtMs = resolvePurchaseAtMsFromOrderDoc(orderDoc);

          const list = await fetchApiProxyListByUser(username);
          if (!list.length) throw new Error('api_proxy_empty_list');

          const providerOrderIdFromDoc = resolveProviderOrderIdFromOrderDoc(orderDoc);
          const effectiveFornecedorOrderId = fornecedorOrderId || providerOrderIdFromDoc;
          const want = {
            fornecedorOrderId: effectiveFornecedorOrderId,
            qty: resolveContractedQty(orderDoc),
            serviceId: resolveProviderServiceId(orderDoc),
            purchaseAtMs
          };

          let pedido = null;
          let bestScore = -1;
          for (const p of list) {
            const s = scorePedidoMatch(p, want);
            if (s > bestScore) {
              bestScore = s;
              pedido = p;
            }
          }
          if (!pedido || bestScore < 0) throw new Error('api_proxy_no_matching_pedido');
          if (effectiveFornecedorOrderId && bestScore < 900) throw new Error('api_proxy_missing_target_orderid');
          if (!effectiveFornecedorOrderId) {
            const pQty = toInt(pedido.quantity);
            const pService = toInt(pedido.service_id || pedido.service);
            const okWeak = (!!(want.serviceId && pService === want.serviceId)) || (!!(want.qty && pQty === want.qty));
            if (!okWeak) throw new Error('api_proxy_ambiguous_match');
          }
          if (!pedido || typeof pedido !== 'object') throw new Error('api_proxy_invalid_pedido');
          const startCount = toInt(pedido.start_count);
          if (!(startCount > 0)) throw new Error('api_proxy_missing_start_count');

          const createdIso = toIsoFromProvider(pedido.created_at || pedido.created || '') || ((purchaseAtMs > 0) ? new Date(purchaseAtMs).toISOString() : new Date().toISOString());
          const upd = await ordersCol.updateOne(filter, { $set: { initialFollowersCount: Math.floor(startCount), initialFollowersCheckedAt: createdIso } });
          if (upd && upd.matchedCount) job.ok += 1;
          else job.failed += 1;
        } catch (e) {
          job.failed += 1;
          job.lastError = e?.message || String(e);
        } finally {
          job.done += 1;
          await sleep(250);
        }
      }
      if (job.status === 'running' && job.done >= (Array.isArray(job.targets) ? job.targets.length : 0)) {
        job.status = 'done';
        job.finishedAt = new Date().toISOString();
      }
    } catch (e) {
      job.status = 'error';
      job.lastError = e?.message || String(e);
      job.finishedAt = new Date().toISOString();
    } finally {
      job._runnerActive = false;
    }
  })();
}

app.post('/api/painel/gerenciamento-seguidores/fix-initial/start', requireAdmin, async (req, res) => {
  try {
    if (global.followersMgmtFixInitialJob && global.followersMgmtFixInitialJob.status === 'running') {
      return res.json({ ok: true, job: followersMgmtSerializeFixInitialJob(global.followersMgmtFixInitialJob) });
    }
    const rawTargets = (req.body && Array.isArray(req.body.targets)) ? req.body.targets : [];
    if (!rawTargets.length) return res.status(400).json({ ok: false, error: 'empty_targets' });
    const unique = [];
    const seen = new Set();
    for (const r of rawTargets) {
      const oid = String(r && r.orderId ? r.orderId : '').trim();
      if (!oid) continue;
      if (seen.has(oid)) continue;
      seen.add(oid);
      unique.push({
        orderId: oid,
        fornecedorOrderId: String(r && r.fornecedorOrderId ? r.fornecedorOrderId : '').trim(),
        username: String(r && r.username ? r.username : '').trim(),
        purchaseAtMs: Number(r && r.purchaseAtMs ? r.purchaseAtMs : 0) || 0,
        tipo: String(r && r.tipo ? r.tipo : '').trim()
      });
      if (unique.length >= 5000) break;
    }
    unique.sort((a, b) => Number(a.purchaseAtMs || 0) - Number(b.purchaseAtMs || 0));
    const job = {
      id: String(Date.now()) + '_' + String(Math.random()).slice(2),
      status: 'running',
      startedAt: new Date().toISOString(),
      finishedAt: null,
      total: unique.length,
      done: 0,
      ok: 0,
      failed: 0,
      skipped: 0,
      lastUsername: null,
      lastError: null,
      targets: unique
    };
    global.followersMgmtFixInitialJob = job;
    followersMgmtKickFixInitialJob();
    return res.json({ ok: true, job: followersMgmtSerializeFixInitialJob(job) });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.get('/api/painel/gerenciamento-seguidores/fix-initial/status', requireAdmin, async (req, res) => {
  try {
    const job = global.followersMgmtFixInitialJob || null;
    if (!job) return res.json({ ok: true, job: null });
    return res.json({ ok: true, job: followersMgmtSerializeFixInitialJob(job) });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

app.post('/api/painel/gerenciamento-seguidores/refil2/use-mongo-initial/mark', requireAdmin, async (req, res) => {
  try {
    const body = (req && req.body && typeof req.body === 'object') ? req.body : {};
    const rawTargets = Array.isArray(body.targets) ? body.targets : [];
    if (!rawTargets.length) return res.status(400).json({ ok: false, error: 'empty_targets' });

    const { getCollection } = require('./mongodbClient');
    const ordersCol = await getCollection('checkout_orders');
    const ovCol = await getCollection('refil2_initial_overrides');
    const { ObjectId } = require('mongodb');

    const nowIso = new Date().toISOString();
    const adminUser = (req && req.session && req.session.adminUser && req.session.adminUser.username) ? String(req.session.adminUser.username) : 'admin';
    const toInt = (v) => {
      const n = Number(String(v == null ? '' : v).replace(/[^\d\-]/g, ''));
      return Number.isFinite(n) ? Math.trunc(n) : 0;
    };
    const pickAdd = (doc, key) => {
      try {
        const mapPaid = (doc && doc.additionalInfoMapPaid && typeof doc.additionalInfoMapPaid === 'object') ? doc.additionalInfoMapPaid : {};
        const map = (doc && doc.additionalInfoMap && typeof doc.additionalInfoMap === 'object') ? doc.additionalInfoMap : {};
        if (typeof mapPaid[key] !== 'undefined') return mapPaid[key];
        if (typeof map[key] !== 'undefined') return map[key];
        const arrPaid = Array.isArray(doc && doc.additionalInfoPaid) ? doc.additionalInfoPaid : [];
        const itPaid = arrPaid.find(x => x && String(x.key || '').trim() === key);
        if (itPaid && typeof itPaid.value !== 'undefined') return itPaid.value;
        const arr = Array.isArray(doc && doc.additionalInfo) ? doc.additionalInfo : [];
        const it = arr.find(x => x && String(x.key || '').trim() === key);
        if (it && typeof it.value !== 'undefined') return it.value;
      } catch (_) {}
      return '';
    };
    const resolveContractedQty = (doc) => {
      try {
        if (typeof doc?.quantidade === 'number' && Number.isFinite(doc.quantidade)) return Math.trunc(doc.quantidade);
        if (typeof doc?.qtd === 'number' && Number.isFinite(doc.qtd)) return Math.trunc(doc.qtd);
        const q0 = toInt(pickAdd(doc, 'quantidade'));
        return q0 > 0 ? q0 : 0;
      } catch (_) {
        return 0;
      }
    };

    const ops = [];
    const orderOps = [];
    const seen = new Set();
    for (const t of rawTargets) {
      const mongoOrderId = String(t && t.orderId ? t.orderId : '').trim();
      const fornecedorOrderId = String(t && t.fornecedorOrderId ? t.fornecedorOrderId : '').trim();
      if (!fornecedorOrderId) continue;
      const key = `${fornecedorOrderId}|${mongoOrderId}`;
      if (seen.has(key)) continue;
      seen.add(key);

      let manualInitial = null;
      if (mongoOrderId && /^[0-9a-fA-F]{24}$/.test(mongoOrderId)) {
        try {
          const doc = await ordersCol.findOne(
            { _id: new ObjectId(mongoOrderId) },
            { projection: { initialFollowersCount: 1, quantidade: 1, qtd: 1, additionalInfoMapPaid: 1, additionalInfoPaid: 1, additionalInfoMap: 1, additionalInfo: 1 } }
          );
          const base = (doc && typeof doc.initialFollowersCount === 'number' && Number.isFinite(doc.initialFollowersCount) && doc.initialFollowersCount > 0)
            ? Math.trunc(doc.initialFollowersCount)
            : 0;
          const contracted = resolveContractedQty(doc);
          const computed = (base > 0 && contracted > 0) ? (base + contracted) : 0;
          if (computed > 0) manualInitial = computed;
        } catch (_) {
          manualInitial = null;
        }
      }

      ops.push({
        updateOne: {
          filter: { orderId: fornecedorOrderId },
          update: {
            $set: {
              orderId: fornecedorOrderId,
              useMongoStartCount: true,
              mongoOrderId: mongoOrderId || null,
              ...(manualInitial != null ? { manualInitial, manualInitialUpdatedAt: nowIso, manualInitialUpdatedBy: adminUser } : {}),
              updatedAt: nowIso,
              updatedBy: adminUser
            }
          },
          upsert: true
        }
      });

      if (mongoOrderId && /^[0-9a-fA-F]{24}$/.test(mongoOrderId)) {
        try {
          orderOps.push({
            updateOne: {
              filter: { _id: new ObjectId(mongoOrderId) },
              update: {
                $set: {
                  refil2UseMongoInitial: true,
                  refil2UseMongoInitialAt: nowIso,
                  refil2UseMongoInitialBy: adminUser
                }
              },
              upsert: false
            }
          });
        } catch (_) {}
      }
      if (ops.length >= 2000) break;
    }
    if (!ops.length) return res.status(400).json({ ok: false, error: 'no_valid_targets' });

    const upd1 = await ovCol.bulkWrite(ops, { ordered: false });
    let upd2 = null;
    if (orderOps.length) {
      try { upd2 = await ordersCol.bulkWrite(orderOps, { ordered: false }); } catch (_) { upd2 = null; }
    }
    return res.json({ ok: true, overrides: { matched: upd1.matchedCount || 0, upserted: (upd1.upsertedCount || 0) }, orders: { updated: upd2 ? (upd2.modifiedCount || 0) : 0 } });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

function followersMgmtSerializeVerifyFilteredJob(jobRaw) {
  const job = jobRaw || null;
  if (!job) return null;
  return {
    id: job.id,
    status: job.status,
    startedAt: job.startedAt,
    finishedAt: job.finishedAt,
    pausedAt: job.pausedAt || null,
    resumedAt: job.resumedAt || null,
    force: !!job.force,
    total: job.total,
    done: job.done,
    ok: job.ok,
    failed: job.failed,
    lastUsername: job.lastUsername || null,
    lastError: job.lastError || null,
    lastFailedUsernames: Array.isArray(job.lastFailedUsernames) ? job.lastFailedUsernames.slice(0, 50) : []
  };
}

function followersMgmtKickVerifyFilteredJob() {
  const job = global.followersMgmtVerifyFilteredJob || null;
  if (!job) return;
  if (job._runnerActive) return;
  if (job.status !== 'running') return;
  job._runnerActive = true;

  const reqLike = { session: { adminUser: { username: 'system' } }, realIP: 'followers_verify_filtered', ip: 'followers_verify_filtered' };
  (async () => {
    try {
      const targets = Array.isArray(job.targets) ? job.targets : [];
      try { console.log(`🔎 [followers-verify-filtered] start job=${String(job.id || '')} total=${targets.length}`); } catch (_) {}
      while (job.status === 'running' && job.done < targets.length) {
        const u = targets[job.done];
        job.lastUsername = u;
        job.lastError = null;
        const stepStartedAtMs = Date.now();
        try {
          const out = await followersMgmtGetCurrent(reqLike, u, !!job.force);
          try {
            const b = out && out.body ? out.body : null;
            const src = b ? String(b.source || '') : '';
            const priv = (b && typeof b.isPrivate === 'boolean') ? (b.isPrivate ? '1' : '0') : '';
            const fc = (b && typeof b.followersCount === 'number') ? String(b.followersCount) : '';
            const ok = b && b.ok ? '1' : '0';
            console.log(`🔎 [followers-verify-filtered] job=${String(job.id || '')} i=${job.done + 1}/${targets.length} ok=${ok} @${u} source=${src} private=${priv} fc=${fc} ms=${Date.now() - stepStartedAtMs}`);
          } catch (_) {}
          if (out && out.body && out.body.ok) job.ok += 1;
          else job.failed += 1;
          if (out && out.body && out.body.error) {
            job.lastError = String(out.body.error || '');
            if (!job.lastFailedUsernames) job.lastFailedUsernames = [];
            if (Array.isArray(job.lastFailedUsernames)) {
              job.lastFailedUsernames.push(u);
              if (job.lastFailedUsernames.length > 200) job.lastFailedUsernames.splice(0, job.lastFailedUsernames.length - 200);
            }
          }
        } catch (e) {
          job.failed += 1;
          job.lastError = e?.message || String(e);
          try { console.warn(`🔎 [followers-verify-filtered] job=${String(job.id || '')} i=${job.done + 1}/${targets.length} fail @${u} ms=${Date.now() - stepStartedAtMs}:`, job.lastError); } catch (_) {}
          if (!job.lastFailedUsernames) job.lastFailedUsernames = [];
          if (Array.isArray(job.lastFailedUsernames)) {
            job.lastFailedUsernames.push(u);
            if (job.lastFailedUsernames.length > 200) job.lastFailedUsernames.splice(0, job.lastFailedUsernames.length - 200);
          }
        } finally {
          job.done += 1;
        }
      }
      if (job.status === 'running' && job.done >= (Array.isArray(job.targets) ? job.targets.length : 0)) {
        job.status = 'done';
        job.finishedAt = new Date().toISOString();
      }
    } catch (e) {
      job.status = 'error';
      job.lastError = e?.message || String(e);
      job.finishedAt = new Date().toISOString();
    } finally {
      job._runnerActive = false;
    }
  })();
}

app.post('/api/painel/gerenciamento-seguidores/verify-filtered/start', requireAdmin, async (req, res) => {
  try {
    if (global.followersMgmtVerifyFilteredJob && global.followersMgmtVerifyFilteredJob.status === 'running') {
      return res.json({ ok: true, job: followersMgmtSerializeVerifyFilteredJob(global.followersMgmtVerifyFilteredJob) });
    }

    const safe = (v) => String(v == null ? '' : v).trim();
    const normalizeUsernameKey = (u) => {
      const s0 = safe(u);
      if (!s0) return '';
      const s1 = s0.startsWith('@') ? s0.slice(1) : s0;
      return s1.toLowerCase().trim();
    };

    const rawList = (req.body && Array.isArray(req.body.usernames)) ? req.body.usernames : [];
    const force = String((req.body && req.body.force) || req.query.force || '0').trim() === '1';
    const usernames = [];
    const seen = new Set();
    for (const r of rawList) {
      const u = normalizeUsernameKey(r);
      if (!u) continue;
      if (seen.has(u)) continue;
      seen.add(u);
      usernames.push(u);
      if (usernames.length >= 5000) break;
    }
    if (!usernames.length) return res.status(400).json({ ok: false, error: 'empty_usernames' });

    const job = {
      id: String(Date.now()) + '_' + String(Math.random()).slice(2),
      status: 'running',
      startedAt: new Date().toISOString(),
      finishedAt: null,
      force,
      total: usernames.length,
      done: 0,
      ok: 0,
      failed: 0,
      lastUsername: null,
      lastError: null,
      lastFailedUsernames: [],
      targets: usernames
    };
    global.followersMgmtVerifyFilteredJob = job;
    followersMgmtKickVerifyFilteredJob();
    return res.json({ ok: true, job: followersMgmtSerializeVerifyFilteredJob(job) });
  } catch (e) {
    return res.status(500).json({ ok: false, error: e?.message || String(e) });
  }
});

