        if (!v) return '';
        if (!/^https?:\/\//i.test(v)) {
          if (/^www\./i.test(v)) v = `https://${v}`;
          else if (/^instagram\.com\//i.test(v)) v = `https://${v}`;
          else if (/^\/\/+/i.test(v)) v = `https:${v}`;
        }
        v = v.split('#')[0].split('?')[0];
        const m = v.match(/^https?:\/\/(www\.)?instagram\.com\/(p|reel|tv)\/([A-Za-z0-9_-]+)\/?$/i);
        if (!m) return '';
